<span class="cm">// ─────────────────────────────────────────────────────────────────────────</span>
<span class="cm">// ❌ Buggy:  widgetRegistry.push(widget);  // push only, never remove</span>
<span class="cm">// ✅ Fixed:  widgetRegistry.push(widget);  // push on add</span>
<span class="cm">//            const i = widgetRegistry.findIndex(w =&gt; w.id === id);</span>
<span class="cm">//            widgetRegistry.splice(i, 1);  // splice on remove</span>

