<script>
'use strict';

/* ═══════════════════════════════════════════════════
   SHARED STATE
═══════════════════════════════════════════════════ */
let widgetIdCounter = 0;

// ── Simulated memory tracking (in KB) ──
// Each widget: ~12 KB of "data" (simulated)
// Each leaked listener: ~2 KB overhead (simulated)
// Each leaked DOM ref: ~8 KB overhead (simulated)
const KB_PER_WIDGET_DATA     = 12;
const KB_PER_LEAKED_LISTENER = 2;
const KB_PER_LEAKED_DOM_REF  = 8;
const KB_PER_ACTIVE_WIDGET   = 10; // legitimate in-use memory

// ── Global counters ──
const counters = {
  totalCreated:       0,
  buggyActiveDom:     0,
  leakedListeners:    0,
  leakedRefs:         0,
  fixedActiveDom:     0,
  cleaned:            0,
};

// ── Graph history (last N points) ──
const GRAPH_POINTS = 40;
const buggyHistory = Array(GRAPH_POINTS).fill(0);
const fixedHistory = Array(GRAPH_POINTS).fill(0);


/* ═══════════════════════════════════════════════════
   BUGGY WIDGET MANAGER
   Three deliberate leak patterns:
   1. Anonymous listeners (can't be removed)
   2. Global registry array (never spliced)
   3. External data cache (keys never deleted)
   + Map holding element → handlers (never deleted)
═══════════════════════════════════════════════════ */
const buggyRegistry = [];   // ❌ entries never removed
const buggyEventMap = new Map(); // ❌ entries never deleted
const buggyDataCache = {};  // ❌ keys never deleted
let   buggyListenerCount = 0;

const WIDGET_TYPES = [
  { icon: '📈', label: 'Revenue',    color: '#6c63ff' },
  { icon: '👥', label: 'Users',      color: '#00d4aa' },
  { icon: '🛒', label: 'Orders',     color: '#ff4d6d' },
  { icon: '⚡', label: 'Perf',       color: '#ffb347' },
  { icon: '💾', label: 'Storage',    color: '#43e97b' },
  { icon: '🌐', label: 'Requests',   color: '#38bdf8' },
  { icon: '🔔', label: 'Alerts',     color: '#f472b6' },
  { icon: '🔒', label: 'Security',   color: '#a78bfa' },
];

function makeWidgetId() {
  return `w-${++widgetIdCounter}-${Date.now().toString(36)}`;
}

function randomType() {
  return WIDGET_TYPES[Math.floor(Math.random() * WIDGET_TYPES.length)];
}

function randomValue() {
  return Math.floor(Math.random() * 9900 + 100);
}

// Build the DOM element for a widget (shared between buggy/fixed)
function buildWidgetEl(id, type, value, onRemove) {
  const el = document.createElement('div');
  el.className = 'widget-item';
  el.dataset.id = id;

  const pct = Math.floor(Math.random() * 80 + 10);

  el.innerHTML = `
    <button class="w-remove" title="Remove widget">✕</button>
    <div class="w-title">${type.icon} ${type.label}</div>
    <div class="w-value">${value.toLocaleString()}</div>
    <div class="w-bar">
      <div class="w-bar-fill" style="width:${pct}%;background:${type.color}"></div>
    </div>
    <div style="font-size:.7rem;color:var(--text-dim)">ID: ${id.slice(0,10)}</div>
  `;

  el.querySelector('.w-remove').addEventListener('click', (e) => {
    e.stopPropagation();
    onRemove(id, el);
  });

  return el;
}

// ── ADD (buggy) ──
function addWidgetBuggy() {
  const id    = makeWidgetId();
  const type  = randomType();
  const value = randomValue();

  const el = buildWidgetEl(id, type, value, removeBuggyWidget);

  // ❌ LEAK 1: anonymous mouseover listener — no reference kept, can never be removed
  el.addEventListener('mouseover', () => {
    // This closure captures `el` and `id` — keeping them alive
    void el.dataset.id;
    void id;
  });

  // ❌ LEAK 2: anonymous interval that references el — never cleared
  const intervalId = setInterval(() => {
    const fill = el.querySelector('.w-bar-fill');
    if (fill) {
      const newPct = Math.floor(Math.random() * 80 + 10);
      fill.style.width = newPct + '%';
    }
  }, 2000);

  // ❌ LEAK 3: store named click handler in Map but never delete the Map entry
  const clickHandler = () => log(`Buggy widget ${id} clicked`, 'warn');
  buggyEventMap.set(el, { clickHandler, intervalId });
  el.addEventListener('click', clickHandler);
  buggyListenerCount += 2; // mouseover + click (anonymous, can't remove)

  // ❌ LEAK 4: push to global registry — never spliced out
  buggyRegistry.push({ id, el, type, value });

  // ❌ LEAK 5: write to data cache — key never deleted
  buggyDataCache[id] = {
    title: type.label,
    value,
    history: new Array(100).fill(0).map(() => Math.random()), // some bulk data
    timestamp: Date.now(),
  };

  // Mount
  const grid = document.getElementById('buggy-grid');
  const empty = grid.querySelector('.empty-state');
  if (empty) empty.remove();
  grid.appendChild(el);

  // Update counters
  counters.totalCreated++;
  counters.buggyActiveDom++;
  counters.leakedListeners = buggyListenerCount; // will only grow

  updateLeakList('buggy', id, type.label, 'active');
  updateCounterDisplay();
  log(`[BUGGY] Added widget "${type.label}" (${id.slice(0,12)})`, 'warn');
}

// ── REMOVE (buggy) ──
function removeBuggyWidget(id, el) {
  // ❌ Only removes from DOM — all references above still hold the object!
  el.remove();

  // The interval is still running (leaked!)
  // buggyRegistry still has { id, el, ... }  → el is a detached DOM node in memory
  // buggyEventMap still has el → { clickHandler, intervalId }
  // buggyDataCache still has buggyDataCache[id]
  // The anonymous mouseover handler still closes over el

  counters.buggyActiveDom = Math.max(0, counters.buggyActiveDom - 1);
  // leakedRefs grows because registry was NOT cleaned:
  counters.leakedRefs = buggyRegistry.length; // still contains removed entries!

  updateLeakList('buggy', id, '???', 'leaked');
  updateCounterDisplay();
  updateBuggyStats();

  // Show empty state if grid is empty
  const grid = document.getElementById('buggy-grid');
  if (!grid.querySelector('.widget-item')) {
    grid.innerHTML = '<div class="empty-state">All widgets removed — but references still leak!</div>';
  }

  log(`[BUGGY] Removed widget DOM node — but ${buggyRegistry.length} refs, ${buggyListenerCount} listeners still retained!`, 'error');
}

// ── CLEAR ALL (buggy) ──
function clearAllBuggy() {
  const grid = document.getElementById('buggy-grid');
  const widgets = grid.querySelectorAll('.widget-item');
  widgets.forEach(el => {
    const id = el.dataset.id;
    el.remove();
    updateLeakList('buggy', id, '???', 'leaked');
  });
  counters.buggyActiveDom = 0;
  counters.leakedRefs     = buggyRegistry.length;
  updateCounterDisplay();
  updateBuggyStats();
  grid.innerHTML = '<div class="empty-state">All removed — but ' + buggyRegistry.length + ' leaked references remain!</div>';
  log(`[BUGGY] Cleared all DOM nodes — but ${buggyRegistry.length} entries still in registry, ${buggyListenerCount} listeners still attached to detached nodes!`, 'error');
}


/* ═══════════════════════════════════════════════════
   FIXED WIDGET MANAGER
   Every reference created on add is released on remove.
═══════════════════════════════════════════════════ */
const fixedRegistry  = [];
const fixedEventMap  = new Map();
const fixedDataCache = {};

// ── ADD (fixed) ──
function addWidgetFixed() {
  const id    = makeWidgetId();
  const type  = randomType();
  const value = randomValue();

  const el = buildWidgetEl(id, type, value, removeFixedWidget);

  // ✅ Named handler — can be passed to removeEventListener
  function hoverHandler() {
    void id; // only captures id (a primitive string), not the DOM node
  }
  el.addEventListener('mouseover', hoverHandler);

  // ✅ Interval stored so it can be cleared
  const intervalId = setInterval(() => {
    const fill = el.querySelector('.w-bar-fill');
    if (fill) {
      const newPct = Math.floor(Math.random() * 80 + 10);
      fill.style.width = newPct + '%';
    }
  }, 2000);

  // ✅ Named click handler stored in Map — will be retrieved and removed later
  const clickHandler = () => log(`Fixed widget ${id} clicked`, 'ok');
  fixedEventMap.set(el, { clickHandler, hoverHandler, intervalId });
  el.addEventListener('click', clickHandler);

  // ✅ Push to registry — will be spliced out on remove
  fixedRegistry.push({ id, el, type, value });

  // ✅ Write to cache — key will be deleted on remove
  fixedDataCache[id] = {
    title: type.label,
    value,
    history: new Array(100).fill(0).map(() => Math.random()),
    timestamp: Date.now(),
  };

  // Mount
  const grid = document.getElementById('fixed-grid');
  const empty = grid.querySelector('.empty-state');
  if (empty) empty.remove();
  grid.appendChild(el);

  counters.totalCreated++;
  counters.fixedActiveDom++;
  updateLeakList('fixed', id, type.label, 'active');
  updateCounterDisplay();
  log(`[FIXED] Added widget "${type.label}" (${id.slice(0,12)})`, 'ok');
}

// ── REMOVE (fixed) ──
function removeFixedWidget(id, el) {
  // ✅ Step 1: retrieve handlers and remove all listeners + clear interval
  const handlers = fixedEventMap.get(el);
  if (handlers) {
    el.removeEventListener('click',     handlers.clickHandler);
    el.removeEventListener('mouseover', handlers.hoverHandler);
    clearInterval(handlers.intervalId);  // ✅ interval cleared!
    fixedEventMap.delete(el);            // ✅ Map no longer holds el
  }

  // ✅ Step 2: remove from registry array
  const idx = fixedRegistry.findIndex(w => w.id === id);
  if (idx !== -1) fixedRegistry.splice(idx, 1);

  // ✅ Step 3: delete from data cache
  delete fixedDataCache[id];

  // ✅ Step 4: remove from DOM — NOW GC can collect it
  el.remove();

  counters.fixedActiveDom = Math.max(0, counters.fixedActiveDom - 1);
  counters.cleaned++;
  updateLeakList('fixed', id, '✓ freed', 'cleaned');
  updateCounterDisplay();
  updateFixedStats();

  const grid = document.getElementById('fixed-grid');
  if (!grid.querySelector('.widget-item')) {
    grid.innerHTML = '<div class="empty-state">All widgets removed and properly cleaned up ✓</div>';
  }

  log(`[FIXED] Removed widget ${id.slice(0,12)} — listeners removed, interval cleared, registry spliced, cache deleted. GC can now collect.`, 'ok');
}

// ── CLEAR ALL (fixed) ──
function clearAllFixed() {
  const grid = document.getElementById('fixed-grid');
  const widgets = [...grid.querySelectorAll('.widget-item')];
  widgets.forEach(el => {
    const id = el.dataset.id;
    removeFixedWidget(id, el);
  });
  if (!grid.querySelector('.widget-item')) {
    grid.innerHTML = '<div class="empty-state">All removed and fully cleaned up ✓</div>';
  }
  log(`[FIXED] Cleared all widgets cleanly. Memory freed.`, 'ok');
}


/* ═══════════════════════════════════════════════════
   UI HELPERS
═══════════════════════════════════════════════════ */

// ── Leak / cleanup list entries ──
const leakListEntries = { buggy: {}, fixed: {} };

function updateLeakList(side, id, label, state) {
  const listEl = document.getElementById(`${side}-leak-list`);

  // Remove placeholder
  const placeholder = listEl.querySelector('div[style]');
  if (placeholder) placeholder.remove();

  const shortId = id.slice(0, 12);
  const key = `${side}-${id}`;

  if (leakListEntries[side][key]) {
    // Update existing entry
    const entry = leakListEntries[side][key];
    entry.className = `leak-entry ${state}`;
    entry.querySelector('.le-badge').textContent =
      state === 'active'  ? 'ACTIVE'  :
      state === 'leaked'  ? 'LEAKED'  : 'FREED';
    entry.querySelector('.le-info').textContent =
      state === 'leaked'  ? 'DOM removed, refs remain' :
      state === 'cleaned' ? 'All refs released'        : 'In DOM';
  } else {
    // Create new entry
    const entry = document.createElement('div');
    entry.className = `leak-entry ${state}`;
    entry.innerHTML = `
      <div class="le-dot"></div>
      <div class="le-name">${label}</div>
      <div class="le-info">${shortId}</div>
      <div class="le-badge">${state === 'active' ? 'ACTIVE' : state === 'leaked' ? 'LEAKED' : 'FREED'}</div>
    `;
    listEl.appendChild(entry);
    listEl.scrollTop = listEl.scrollHeight;
    leakListEntries[side][key] = entry;
  }
}

// ── Stats bars ──
function updateBuggyStats() {
  document.getElementById('bs-dom').textContent       = counters.buggyActiveDom;
  document.getElementById('bs-refs').textContent      = buggyRegistry.length;
  document.getElementById('bs-listeners').textContent = buggyListenerCount;
}

function updateFixedStats() {
  document.getElementById('fs-dom').textContent       = counters.fixedActiveDom;
  document.getElementById('fs-refs').textContent      = fixedRegistry.length;
  document.getElementById('fs-listeners').textContent = fixedEventMap.size * 2;
}

// ── Counter display ──
function updateCounterDisplay() {
  document.getElementById('cnt-total').textContent            = counters.totalCreated;
  document.getElementById('cnt-active-buggy').textContent     = counters.buggyActiveDom;
  document.getElementById('cnt-leaked-listeners').textContent = buggyListenerCount;
  document.getElementById('cnt-leaked-refs').textContent      = buggyRegistry.length;
  document.getElementById('cnt-active-fixed').textContent     = counters.fixedActiveDom;
  document.getElementById('cnt-cleaned').textContent          = counters.cleaned;

  // Simulated memory
  const buggyMem =
    counters.buggyActiveDom  * KB_PER_ACTIVE_WIDGET +
    buggyRegistry.length     * KB_PER_LEAKED_DOM_REF +
    buggyListenerCount       * KB_PER_LEAKED_LISTENER;

  const fixedMem =
    counters.fixedActiveDom  * KB_PER_ACTIVE_WIDGET;

  document.getElementById('cnt-mem-buggy').textContent = buggyMem  + ' KB';
