<script>
'use strict';

/* ─────────────────────────────────────────────────────────────────
   Shared utilities
───────────────────────────────────────────────────────────────── */
const WIDGET_NAMES = [
    'CPU Usage','Mem Usage','Disk I/O','Net Tx','Net Rx',
    'GPU Temp','Fan Speed','Battery','Uptime','Requests',
    'Errors','Latency','Cache Hit','Queue Len','Threads'
];

const WIDGET_COLORS = [
    '#4f8ef7','#a78bfa','#f7a94f','#4fca74','#f74f4f',
    '#38bdf8','#fb7185','#34d399','#fbbf24','#a3e635'
];

let widgetCounter = 0;

function makeWidgetId() { return ++widgetCounter; }

function randomValue() { return Math.floor(Math.random() * 100); }

function randomName()  { return WIDGET_NAMES[Math.floor(Math.random() * WIDGET_NAMES.length)]; }

function randomColor() { return WIDGET_COLORS[Math.floor(Math.random() * WIDGET_COLORS.length)]; }

function timestamp() {
    const d = new Date();
    return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}:${String(d.getSeconds()).padStart(2,'0')}.${String(d.getMilliseconds()).padStart(3,'0')}`;
}

/* ── Log ── */
const logList = document.getElementById('log-list');
function log(msg, type = 'info') {
    const li = document.createElement('li');
    li.className = type;
    li.innerHTML = `<span class="ts">${timestamp()}</span>${msg}`;
    logList.prepend(li);
    // Keep log bounded
    while (logList.children.length > 80) logList.removeChild(logList.lastChild);
}

/* ─────────────────────────────────────────────────────────────────
   Chart helper  — simple rolling line chart on a <canvas>
───────────────────────────────────────────────────────────────── */
class RollingChart {
    constructor(canvasId, color) {
        this.canvas  = document.getElementById(canvasId);
        this.ctx     = this.canvas.getContext('2d');
        this.color   = color;
        this.history = new Array(60).fill(0);
        this._resize();
        window.addEventListener('resize', () => this._resize());
    }

    _resize() {
        const rect = this.canvas.parentElement.getBoundingClientRect();
        this.canvas.width  = rect.width  || 400;
        this.canvas.height = 100;
        this.draw();
    }

    push(value) {
        this.history.push(value);
        if (this.history.length > 60) this.history.shift();
        this.draw();
    }

    draw() {
        const { ctx, canvas, history, color } = this;
        const W = canvas.width, H = canvas.height;
        const max = Math.max(...history, 1);

        ctx.clearRect(0, 0, W, H);

        // Grid lines
        ctx.strokeStyle = 'rgba(255,255,255,.05)';
        ctx.lineWidth = 1;
        for (let i = 0; i <= 4; i++) {
            const y = Math.round(H * (i / 4));
            ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
        }

        // Area fill
        const grad = ctx.createLinearGradient(0, 0, 0, H);
        grad.addColorStop(0, color + 'aa');
        grad.addColorStop(1, color + '00');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.moveTo(0, H);
        history.forEach((v, i) => {
            const x = (i / (history.length - 1)) * W;
            const y = H - (v / max) * (H - 8) - 4;
            i === 0 ? ctx.lineTo(x, y) : ctx.lineTo(x, y);
        });
        ctx.lineTo(W, H);
        ctx.closePath();
        ctx.fill();

        // Line
        ctx.strokeStyle = color;
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.beginPath();
        history.forEach((v, i) => {
            const x = (i / (history.length - 1)) * W;
            const y = H - (v / max) * (H - 8) - 4;
            i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
        });
        ctx.stroke();
    }
}

const buggyChart = new RollingChart('buggy-canvas', '#f74f4f');
const fixedChart = new RollingChart('fixed-canvas', '#4fca74');

/* ─────────────────────────────────────────────────────────────────
   ██████  BUGGY DASHBOARD  ██████
   Leaks: anonymous listeners, uncleared intervals,
          persistent DOM refs, never-pruned data cache
───────────────────────────────────────────────────────────────── */
class BuggyDashboard {
    constructor(gridId) {
        this.grid = document.getElementById(gridId);

        // ❌ These arrays/objects accumulate forever
        this.widgetRegistry  = [];   // { id, el, name }
        this.domReferences   = [];   // direct el refs — never pruned
        this.listenerHandles = [];   // listener refs stored but never used to remove
        this.dataCache       = {};   // keyed by id — never deleted
        this.intervalIds     = [];   // interval ids — never cleared

        this.liveCount    = 0;
        this.leakedCount  = 0;
        this.listenerCount = 0;
    }

    addWidget() {
        const id    = makeWidgetId();
        const name  = randomName();
        const color = randomColor();

        // Build DOM element
        const el = document.createElement('div');
        el.className  = 'widget-card';
        el.dataset.id = id;
        el.innerHTML  = `
            <button class="widget-del" title="Remove">✕</button>
            <div class="widget-name">${name}</div>
            <div class="widget-value" style="color:${color}" id="bwv-${id}">${randomValue()}</div>
            <div class="widget-sub">Widget #${id}</div>
        `;

        // ❌ Anonymous listener — reference is lost immediately after push
        //    Cannot call removeEventListener with this later
        const handler = (e) => {
            if (e.target.classList.contains('widget-del')) {
                this._removeFromDOM(id);
            }
            // Closure captures `el`, `id`, `name` — keeps them alive
            this.dataCache[id] = { el, name, ts: Date.now() };
        };
        el.addEventListener('click', handler);
        this.listenerHandles.push(handler); // stored but never used to remove ❌

        // ❌ Interval keeps updating dataCache[id] even after widget removed
        const iv = setInterval(() => {
            const valEl = document.getElementById(`bwv-${id}`);
            if (valEl) valEl.textContent = randomValue();
            // Even when el is removed from DOM, this keeps running
            // and keeps the closure (and el) alive
            this.dataCache[id] = {
                el,          // ❌ strong ref to DOM node
                name,
                value: randomValue(),
                ts: Date.now()
            };
        }, 1500);
        this.intervalIds.push(iv); // never cleared ❌

        // ❌ Push el into domReferences — survives DOM removal
        this.domReferences.push(el);

        // ❌ Registry entry never deleted on remove
        this.widgetRegistry.push({ id, el, name, color });

        this.grid.appendChild(el);

        this.liveCount++;
        this.leakedCount = this.domReferences.length;
        this.listenerCount = this.listenerHandles.length;
        this._updateStats();

        log(`[BUGGY] Added widget #${id} "${name}" — leaked refs: ${this.leakedCount}`, 'leak');
    }

    // Called when the ✕ button is clicked inside a widget
    _removeFromDOM(id) {
        const entry = this.widgetRegistry.find(w => w.id === id);
        if (!entry) return;

        // Animate out
        entry.el.classList.add('removing');
        setTimeout(() => {
            entry.el.remove(); // ✓ removed from live DOM
            // ❌ But domReferences, widgetRegistry, dataCache,
            //    intervalIds, listenerHandles are NOT cleaned up
            this.liveCount = Math.max(0, this.liveCount - 1);
            // leakedCount does NOT decrease — that's the bug
            this._updateStats();
            log(`[BUGGY] Removed widget #${id} from DOM — but ${this.leakedCount} refs still leaked! ☠`, 'leak');
        }, 200);
    }

    removeLastWidget() {
        const last = this.widgetRegistry[this.widgetRegistry.length - 1];
        if (last) this._removeFromDOM(last.id);
        else log('[BUGGY] No widgets to remove', 'info');
    }

    stressTest() {
        for (let i = 0; i < 10; i++) {
            setTimeout(() => this.addWidget(), i * 60);
        }
        setTimeout(() => {
            for (let i = 0; i < 10; i++) {
                setTimeout(() => this.removeLastWidget(), i * 60);
            }
        }, 800);
    }

    clearAll() {
        // Even clearAll doesn't fix the leak in the buggy version
        // because we only remove DOM nodes, not the registry entries
        [...this.widgetRegistry].forEach(w => {
            w.el.remove();
        });
        this.liveCount = 0;
        // ❌ leakedCount, domReferences, intervalIds, dataCache NOT cleared
        this._updateStats();
        log(`[BUGGY] clearAll() — DOM cleared but ${this.leakedCount} refs still retained in memory ☠`, 'leak');
    }

    _updateStats() {
        document.getElementById('buggy-live').textContent      = this.liveCount;
        document.getElementById('buggy-leaked').textContent    = this.leakedCount;
        document.getElementById('buggy-listeners').textContent = this.listenerCount;

        const pct = Math.min(100, (this.leakedCount / 50) * 100);
        document.getElementById('buggy-bar').style.width = Math.max(0, pct) + '%';
        document.getElementById('buggy-bar-pct').textContent  = `${this.leakedCount} leaked objects`;

        buggyChart.push(this.leakedCount);
    }
}

/* ─────────────────────────────────────────────────────────────────
   ██████  FIXED DASHBOARD  ██████
   Proper cleanup: named listeners removed, intervals cleared,
   Map entry deleted → GC can collect everything
───────────────────────────────────────────────────────────────── */
class FixedDashboard {
    constructor(gridId) {
        this.grid = document.getElementById(gridId);

        // ✅ Single Map — easy targeted deletion
        this.widgets = new Map(); // id → { el, handler, iv, name }

        this.liveCount    = 0;
        this.leakedCount  = 0;   // will stay 0
        this.listenerCount = 0;
    }

    addWidget() {
        const id    = makeWidgetId();
        const name  = randomName();
        const color = randomColor();

        const el = document.createElement('div');
        el.className  = 'widget-card';
        el.dataset.id = id;
        el.innerHTML  = `
            <button class="widget-del" title="Remove">✕</button>
            <div class="widget-name">${name}</div>
            <div class="widget-value" style="color:${color}" id="fwv-${id}">${randomValue()}</div>
            <div class="widget-sub">Widget #${id}</div>
        `;

        // ✅ Named handler stored in the Map entry
        const handler = (e) => {
            if (e.target.classList.contains('widget-del')) {
                this.removeWidget(id);
            }
        };
        el.addEventListener('click', handler);

        // ✅ Interval id stored per-widget for later clearInterval
        const iv = setInterval(() => {
            const valEl = document.getElementById(`fwv-${id}`);
            if (valEl) valEl.textContent = randomValue();
        }, 1500);

        // ✅ One entry — contains everything needed for cleanup
        this.widgets.set(id, { el, handler, iv, name, color });

        this.grid.appendChild(el);

        this.liveCount    = this.widgets.size;
        this.listenerCount = this.widgets.size;
        this._updateStats();

        log(`[FIXED] Added widget #${id} "${name}" — total tracked: ${this.widgets.size}`, 'fix');
    }

    removeWidget(id) {
        const entry = this.widgets.get(id);
        if (!entry) return;

        // Animate out then fully clean up
        entry.el.classList.add('removing');
        setTimeout(() => {
            // ✅ 1. Clear the interval — no more background work
            clearInterval(entry.iv);

            // ✅ 2. Remove the named event listener
            entry.el.removeEventListener('click', entry.handler);

            // ✅ 3. Remove from live DOM
            entry.el.remove();

            // ✅ 4. Delete Map entry — drops last strong reference
            //       el, handler, and all closure data are now unreachable
            //       → GC is free to collect them
            this.widgets.delete(id);

            this.liveCount    = this.widgets.size;
            this.listenerCount = this.widgets.size;
            this.leakedCount  = 0; // always stays 0 ✓
            this._updateStats();

            log(`[FIXED] Removed widget #${id} cleanly — 0 leaked refs ✓`, 'fix');
        }, 200);
    }

    removeLastWidget() {
        const keys = [...this.widgets.keys()];
        if (keys.length) this.removeWidget(keys[keys.length - 1]);
        else log('[FIXED] No widgets to remove', 'info');
    }

    stressTest() {
        for (let i = 0; i < 10; i++) {
            setTimeout(() => this.addWidget(), i * 60);
        }
        setTimeout(() => {
            const keys = [...this.widgets.keys()];
            keys.slice(-10).forEach((k, i) => {
                setTimeout(() => this.removeWidget(k), i * 60);
            });
        }, 800);
    }

    clearAll() {
        // ✅ Proper teardown for every widget
        for (const [id] of this.widgets) {
            const entry = this.widgets.get(id);
            clearInterval(entry.iv);
            entry.el.removeEventListener('click', entry.handler);
            entry.el.remove();
        }
        this.widgets.clear(); // ✅ Map is now empty — all refs released
        this.liveCount     = 0;
        this.listenerCount = 0;
        this.leakedCount   = 0;
        this._updateStats();
        log('[FIXED] clearAll() — all intervals cleared, all listeners removed, Map emptied ✓', 'fix');
    }

    _updateStats() {
        document.getElementById('fixed-live').textContent      = this.liveCount;
        document.getElementById('fixed-leaked').textContent    = this.leakedCount;
        document.getElementById('fixed-listeners').textContent = this.listenerCount;

        const pct = Math.min(100, (this.leakedCount / 50) * 100);
        document.getElementById('fixed-bar').style.width = Math.max(2, pct) + '%';
        document.getElementById('fixed-bar-pct').textContent  = `${this.leakedCount} leaked objects`;

        fixedChart.push(this.leakedCount);
    }
}

/* ─────────────────────────────────────────────────────────────────
   Instantiate dashboards
───────────────────────────────────────────────────────────────── */
const buggy = new BuggyDashboard('buggy-grid');
const fixed = new FixedDashboard('fixed-grid');

/* ─────────────────────────────────────────────────────────────────
   Seed with a few initial widgets so the page isn't empty
───────────────────────────────────────────────────────────────── */
(function seed() {
    for (let i = 0; i < 4; i++) {
        setTimeout(() => { buggy.addWidget(); fixed.addWidget(); }, i * 80);
    }
})();

/* ─────────────────────────────────────────────────────────────────
   Periodically redraw charts so they show a timeline even when
   no user interaction is happening
───────────────────────────────────────────────────────────────── */
setInterval(() => {
    buggyChart.push(buggy.leakedCount);
    fixedChart.push(fixed.leakedCount);
}, 2000);

log('Dashboard initialised — try adding and removing widgets on both sides!', 'info');
</script>
</body>
</html>
