  </div>

</div>

<!-- ── Simulated memory chart ── -->
<div class="chart-wrap">
  <h2>📈 Simulated Memory Pressure Over Time</h2>
  <canvas id="memChart" height="180"></canvas>
  <div class="chart-legend">
    <span><span class="legend-dot" style="background:#f87171"></span>Buggy (leaking)</span>
    <span><span class="legend-dot" style="background:#4ade80"></span>Fixed (stable)</span>
