<script>
// ─────────────────────────────────────────────
//  Shared utilities
// ─────────────────────────────────────────────
const WIDGET_TYPES = ['Chart', 'Table', 'Gauge', 'Map', 'Feed', 'Alert', 'KPI', 'Timeline'];
const WIDGET_ICONS = ['📊', '📋', '🎯', '🗺️', '📡', '🚨', '📈', '⏱️'];

let globalIdCounter = 0;

function uid() { return ++globalIdCounter; }

function widgetType() {
    const i = Math.floor(Math.random() * WIDGET_TYPES.length);
    return { name: WIDGET_TYPES[i], icon: WIDGET_ICONS[i] };
}

function now() {
    return new Date().toLocaleTimeString('en-GB', { hour12: false });
}

// ─────────────────────────────────────────────
//  Logger
// ─────────────────────────────────────────────
const logBody = document.getElementById('log-body');

function log(msg, type = 'info') {
    const entry = document.createElement('div');
    entry.className = 'log-entry';
    entry.innerHTML = `<span class="log-time">[${now()}]</span>`
                    + `<span class="log-${type}">${msg}</span>`;
    logBody.prepend(entry);
    // keep log bounded
    while (logBody.children.length > 80) {
        logBody.removeChild(logBody.lastChild);
    }
}

function clearLog() { logBody.innerHTML = ''; }

// ─────────────────────────────────────────────
//  BUGGY Dashboard
//  Intentional leaks:
//    1. leakedRefs[] holds DOM node + data forever
//    2. event listeners are never removed
//    3. a setInterval per widget is never cleared
// ─────────────────────────────────────────────
const buggyDash = (() => {
    // This is the "leak bucket" — references that should be cleaned
    // up on removal but aren't.
    const leakedRefs = {};   // id → { el, data, handler, intervalId }
    const activeIds  = [];   // ids currently visible in the DOM

    let totalCreated = 0;

    function updateStats() {
        const leaked = Object.keys(leakedRefs).length;
        document.getElementById('buggy-active').textContent  = activeIds.length;
        document.getElementById('buggy-created').textContent = totalCreated;
        document.getElementById('buggy-leaked').textContent  = leaked;

        // Simulated memory: each leaked ref costs ~1 unit, capped visually at 100
        const pct = Math.min(100, leaked * 4);
        document.getElementById('buggy-meter').style.width = pct + '%';
        document.getElementById('buggy-mem-pct').textContent = pct + '%';

        renderGhostList();
    }

    function renderGhostList() {
        const container = document.getElementById('buggy-ghost-list');
        const removedIds = Object.keys(leakedRefs).filter(id => !activeIds.includes(id));

        if (removedIds.length === 0) {
            container.innerHTML = '<span style="color:#555;font-size:0.7rem;font-style:italic">None yet…</span>';
            return;
        }
        container.innerHTML = removedIds.map(id => {
            const r = leakedRefs[id];
            return `<div class="ghost-item">widget#${id} "${r.data.name}" — `
                 + `DOM node: ${r.el.isConnected ? '⚠️ connected' : '❌ detached'}, `
                 + `listener: 🔴 still attached, `
                 + `interval: ⏱️ still ticking</div>`;
        }).join('');
    }

    function renderList() {
        const container = document.getElementById('buggy-list');
        if (activeIds.length === 0) {
            container.innerHTML = '<div class="empty-state">No widgets — add some!</div>';
            return;
        }
        container.innerHTML = '';
        // Show newest first
        [...activeIds].reverse().forEach(id => {
            const r = leakedRefs[id];
            const item = document.createElement('div');
            item.className = 'widget-item';
            item.id = 'buggy-widget-' + id;
            item.innerHTML = `
                <div class="widget-info">
                    <div class="widget-name">${r.data.icon} ${r.data.name} #${id}</div>
                    <div class="widget-meta">created ${r.data.createdAt} · clicks: <span id="buggy-clicks-${id}">0</span></div>
                </div>
                <button class="widget-remove-btn" onclick="buggyDash.removeWidget(${id})">Remove</button>
            `;
            container.appendChild(item);
        });
    }

    function addWidget() {
        const id   = uid();
        const type = widgetType();
        const data = {
            id,
            name: type.name,
            icon: type.icon,
            createdAt: now(),
            clickCount: 0,
            // Simulate a large-ish data payload attached to the widget
            payload: new Array(500).fill(`widget-${id}-data`)
        };

        // Create a DOM element (we keep a ref to it in leakedRefs)
        const el = document.createElement('div');
        el.id = 'buggy-el-' + id;
        el.dataset.widgetId = id;

        // ❌ BUG 1: handler closes over `data` and `el` — never removed
        const handler = () => {
            data.clickCount++;
            const span = document.getElementById('buggy-clicks-' + id);
            if (span) span.textContent = data.clickCount;
            log(`[BUGGY] Widget #${id} clicked (count: ${data.clickCount})`, 'warn');
        };
        el.addEventListener('click', handler);

        // ❌ BUG 2: interval keeps running even after widget is "removed"
        const intervalId = setInterval(() => {
            // Simulates a widget polling for data updates.
            // This closure holds `data` and `el` alive.
            data.payload.push(`tick-${Date.now()}`);
        }, 2000);

        // ❌ BUG 3: store everything in leakedRefs — never deleted on removal
        leakedRefs[id] = { el, data, handler, intervalId };
        activeIds.push(id);
        totalCreated++;

        renderList();
        updateStats();
        log(`[BUGGY] Added widget #${id} "${data.name}" — listener registered, interval started`, 'warn');
    }

    function removeWidget(id) {
        const idx = activeIds.indexOf(id);
        if (idx === -1) return;
        activeIds.splice(idx, 1);

        // Remove from DOM — but leakedRefs[id] still exists!
        // The GC CANNOT free el, data, handler, or intervalId
        // because leakedRefs[id] is a live reference.
        const el = document.getElementById('buggy-widget-' + id);
        if (el) el.remove();

        // ❌ We do NOT call: el.removeEventListener('click', handler)
        // ❌ We do NOT call: clearInterval(intervalId)
        // ❌ We do NOT delete leakedRefs[id]

        renderList();
        updateStats();
        log(`[BUGGY] Removed widget #${id} from DOM — but ref, listener & interval still LIVE 🔴`, 'bad');
    }

    function removeLatest() {
        if (activeIds.length === 0) return;
        removeWidget(activeIds[activeIds.length - 1]);
    }

    function addBulk(n) {
        for (let i = 0; i < n; i++) addWidget();
    }

    function reset() {
        // Even on reset, properly clearing everything to let the demo restart
        // (we intentionally show what happens if you DON'T do this normally)
        Object.keys(leakedRefs).forEach(id => {
            clearInterval(leakedRefs[id].intervalId);
            delete leakedRefs[id];
        });
        activeIds.length = 0;
        totalCreated = 0;
        document.getElementById('buggy-list').innerHTML =
            '<div class="empty-state">No widgets — add some!</div>';
        document.getElementById('buggy-ghost-list').innerHTML =
            '<span style="color:#555;font-size:0.7rem;font-style:italic">None yet…</span>';
        updateStats();
        log('[BUGGY] Dashboard reset (intervals cleared for demo hygiene)', 'info');
    }

    return { addWidget, removeWidget, removeLatest, addBulk, reset };
})();


// ─────────────────────────────────────────────
//  FIXED Dashboard
//  Proper cleanup:
//    1. AbortController cancels all listeners at once
//    2. clearInterval() on removal
//    3. widgetRegistry entry deleted → GC can collect
// ─────────────────────────────────────────────
const fixedDash = (() => {
    // WeakMap would work for DOM keys; Map is fine here since we
    // explicitly delete entries — either way the GC can collect.
    const widgetRegistry = new Map();  // id → { el, data, ac, intervalId }
    const activeIds      = [];

    let totalCreated = 0;
    let totalFreed   = 0;

    function updateStats() {
        document.getElementById('fixed-active').textContent  = activeIds.length;
        document.getElementById('fixed-created').textContent = totalCreated;
        document.getElementById('fixed-freed').textContent   = totalFreed;

        // Memory stays flat: only active widgets count
        const pct = Math.min(100, activeIds.length * 4);
        document.getElementById('fixed-meter').style.width = pct + '%';
        document.getElementById('fixed-mem-pct').textContent = pct + '%';

        renderCleanList();
    }

    function renderCleanList() {
        const container = document.getElementById('fixed-clean-list');
        if (totalFreed === 0) {
            container.innerHTML = '<span style="color:#555;font-size:0.7rem;font-style:italic">None yet…</span>';
            return;
        }
        // Show a summary — we can't show freed objects (they're gone!)
        container.innerHTML = `<div class="ghost-item" style="color:#56e39f;background:#0f2a1a;">
            ✅ ${totalFreed} widget(s) fully cleaned up — listeners aborted,
            intervals cleared, registry entries deleted.
            GC is free to collect them.
        </div>`;
    }

    function renderList() {
        const container = document.getElementById('fixed-list');
        if (activeIds.length === 0) {
            container.innerHTML = '<div class="empty-state">No widgets — add some!</div>';
            return;
        }
        container.innerHTML = '';
        [...activeIds].reverse().forEach(id => {
            const r = widgetRegistry.get(id);
            const item = document.createElement('div');
            item.className = 'widget-item';
            item.id = 'fixed-widget-' + id;
            item.innerHTML = `
                <div class="widget-info">
                    <div class="widget-name">${r.data.icon} ${r.data.name} #${id}</div>
                    <div class="widget-meta">created ${r.data.createdAt} · clicks: <span id="fixed-clicks-${id}">0</span></div>
                </div>
                <button class="widget-remove-btn" onclick="fixedDash.removeWidget(${id})">Remove</button>
            `;
            container.appendChild(item);
        });
    }

    function addWidget() {
        const id   = uid();
        const type = widgetType();
        const data = {
            id,
            name: type.name,
            icon: type.icon,
            createdAt: now(),
            clickCount: 0,
            payload: new Array(500).fill(`widget-${id}-data`)
        };

        const el = document.createElement('div');
        el.id = 'fixed-el-' + id;
        el.dataset.widgetId = id;

        // ✅ FIX 1: AbortController — one .abort() removes ALL listeners
        const ac = new AbortController();

        const handler = () => {
            data.clickCount++;
            const span = document.getElementById('fixed-clicks-' + id);
            if (span) span.textContent = data.clickCount;
            log(`[FIXED] Widget #${id} clicked (count: ${data.clickCount})`, 'good');
        };

        // Pass the signal — listener auto-detaches when ac.abort() is called
        el.addEventListener('click', handler, { signal: ac.signal });

        // ✅ FIX 2: Track interval so we can clear it
        const intervalId = setInterval(() => {
            data.payload.push(`tick-${Date.now()}`);
        }, 2000);

        // ✅ FIX 3: Store in registry — will be explicitly deleted on removal
        widgetRegistry.set(id, { el, data, ac, intervalId });
        activeIds.push(id);
        totalCreated++;

        renderList();
        updateStats();
        log(`[FIXED] Added widget #${id} "${data.name}" — AbortController registered`, 'good');
    }

    function removeWidget(id) {
        const idx = activeIds.indexOf(id);
        if (idx === -1) return;
        activeIds.splice(idx, 1);

        const record = widgetRegistry.get(id);
        if (!record) return;

        // ✅ FIX 1: Abort all event listeners — no dangling handlers
        record.ac.abort();

        // ✅ FIX 2: Stop the interval — no more closure references ticking
        clearInterval(record.intervalId);

        // ✅ FIX 3: Remove from DOM
        const el = document.getElementById('fixed-widget-' + id);
        if (el) el.remove();

        // ✅ FIX 4: Delete registry entry — now NOTHING holds a reference
        //           The GC is free to collect el, data, handler, everything.
        widgetRegistry.delete(id);

        totalFreed++;
        renderList();
        updateStats();
        log(`[FIXED] Removed widget #${id} — listener aborted, interval cleared, ref deleted ✅`, 'good');
    }

    function removeLatest() {
        if (activeIds.length === 0) return;
        removeWidget(activeIds[activeIds.length - 1]);
    }

    function addBulk(n) {
        for (let i = 0; i < n; i++) addWidget();
    }

    function reset() {
        [...activeIds].forEach(id => removeWidget(id));
        totalCreated = 0;
        totalFreed   = 0;
        document.getElementById('fixed-list').innerHTML =
            '<div class="empty-state">No widgets — add some!</div>';
        document.getElementById('fixed-clean-list').innerHTML =
            '<span style="color:#555;font-size:0.7rem;font-style:italic">None yet…</span>';
        updateStats();
        log('[FIXED] Dashboard reset cleanly', 'info');
    }

    return { addWidget, removeWidget, removeLatest, addBulk, reset };
})();

// ─────────────────────────────────────────────
//  Boot message
// ─────────────────────────────────────────────
log('Demo loaded. Add widgets to both panels, then remove them and watch the "Leaked Refs" counter.', 'info');
log('In the Buggy panel, removed widgets stay in memory. In the Fixed panel, they are fully released.', 'info');
</script>
</body>
</html>
