    chartHistory.buggy.shift();
    chartHistory.fixed.shift();
  }
  drawChart();
}

/* ═══════════════════════════════════════════════════════════════
   CHART RENDERER  (hand-rolled canvas, no library needed)
═══════════════════════════════════════════════════════════════ */

function drawChart() {
  const canvas = document.getElementById('memChart');
  const dpr    = window.devicePixelRatio || 1;
  const W      = canvas.clientWidth;
  const H      = canvas.clientHeight;

  canvas.width  = W * dpr;
  canvas.height = H * dpr;
  const ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);

  // background
  ctx.fillStyle = '#0f1117';
  ctx.fillRect(0, 0, W, H);

  const data   = chartHistory;
  const n      = data.labels.length;
  if (n < 2) return;

  const PAD  = { top: 16, right: 16, bottom: 28, left: 52 };
  const cW   = W - PAD.left - PAD.right;
  const cH   = H - PAD.top  - PAD.bottom;

  const maxVal = Math.max(...data.buggy, ...data.fixed, 1);

  function xPos(i) { return PAD.left + (i / (n - 1)) * cW; }
  function yPos(v) { return PAD.top  + cH - (v / maxVal) * cH; }

  // grid lines
  ctx.strokeStyle = '#1e293b';
  ctx.lineWidth   = 1;
  for (let t = 0; t <= 4; t++) {
    const y = PAD.top + (t / 4) * cH;
    ctx.beginPath(); ctx.moveTo(PAD.left, y); ctx.lineTo(PAD.left + cW, y);
    ctx.stroke();
    const label = ((maxVal * (4 - t)) / 4).toFixed(0) + ' KB';
    ctx.fillStyle   = '#475569';
    ctx.font        = '10px system-ui';
    ctx.textAlign   = 'right';
    ctx.fillText(label, PAD.left - 6, y + 4);
  }

  // helper: draw a filled-area line
  function drawLine(series, color) {
    ctx.beginPath();
    ctx.moveTo(xPos(0), yPos(series[0]));
    for (let i = 1; i < n; i++) ctx.lineTo(xPos(i), yPos(series[i]));
    ctx.strokeStyle = color;
    ctx.lineWidth   = 2.5;
    ctx.lineJoin    = 'round';
    ctx.stroke();

    // fill
    ctx.lineTo(xPos(n - 1), PAD.top + cH);
    ctx.lineTo(xPos(0),     PAD.top + cH);
    ctx.closePath();
    ctx.fillStyle = color + '22';
    ctx.fill();
  }

  drawLine(data.fixed, '#4ade80');
  drawLine(data.buggy, '#f87171');

  // legend
  const items = [
    { label: 'Buggy (leaking)', color: '#f87171' },
    { label: 'Fixed (clean)',   color: '#4ade80' },
  ];
  let lx = PAD.left + 10;
  items.forEach(item => {
    ctx.fillStyle = item.color;
    ctx.fillRect(lx, PAD.top + 4, 12, 3);
    ctx.fillStyle = '#94a3b8';
    ctx.font      = '11px system-ui';
    ctx.textAlign = 'left';
    ctx.fillText(item.label, lx + 16, PAD.top + 9);
    lx += ctx.measureText(item.label).width + 36;
  });

  // x-axis tick
  ctx.fillStyle = '#475569';
  ctx.font      = '10px system-ui';
  ctx.textAlign = 'center';
  const step = Math.max(1, Math.floor(n / 8));
  for (let i = 0; i < n; i += step) {
    ctx.fillText(data.labels[i], xPos(i), H - PAD.bottom + 14);
  }
}

window.addEventListener('resize', drawChart);

/* ═══════════════════════════════════════════════════════════════
   BUGGY IMPLEMENTATION
   Every removed widget keeps its DOM node, closure, and interval
   alive inside `leakyRegistry`.
═══════════════════════════════════════════════════════════════ */

const leakyRegistry = [];   // <-- the leak: never cleaned up

const buggyState = {
  activeWidgets : [],   // { id, el, intervalId }
  totalAdded    : 0,
  leakedCount   : 0,    // grows even after removal
};

function buggyAddWidget() {
  const id   = ++buggyState.totalAdded;
  const name = WIDGET_NAMES[id % WIDGET_NAMES.length];

  // Build DOM node
  const card = document.createElement('div');
  card.className  = 'widget-card';
  card.dataset.id = id;

  const nameEl  = document.createElement('div');
  nameEl.className = 'widget-name';
  nameEl.textContent = name;

  const valEl   = document.createElement('div');
  valEl.className  = 'widget-value';
  valEl.textContent = randomMetric();

  const unitEl  = document.createElement('div');
  unitEl.className = 'widget-unit';
  unitEl.textContent = '% utilisation';

  const rmBtn   = document.createElement('button');
  rmBtn.className   = 'widget-remove-btn';
  rmBtn.textContent = '✕';

  card.append(nameEl, valEl, unitEl, rmBtn);

  // ── BUG 1: event listener stored in closure but never removed ──
  // The handler closes over `card` and `entry`, keeping both alive.
  const clickHandler = () => {
    valEl.style.color = '#f59e0b'; // just to do something
    log(`[BUGGY] Widget #${id} clicked — listener still alive after removal!`, 'leak');
  };
  card.addEventListener('click', clickHandler);

  // ── BUG 2: interval never cleared ──
  const intervalId = setInterval(() => {
    valEl.textContent = randomMetric();
  }, 800 + Math.random() * 400);

  rmBtn.addEventListener('click', (e) => {
    e.stopPropagation();
    buggyRemoveById(id);
  });

  // ── BUG 3: registry entry is never deleted ──
  const entry = {
    id,
    name,
    domNode      : card,          // strong DOM reference
    clickHandler,                 // strong function reference
    intervalId,                   // running timer
    // simulate a large retained payload (e.g. cached data, event history)
    dataBuffer   : new Array(500).fill(`widget-${id}-data`),
  };
  leakyRegistry.push(entry);

  document.getElementById('buggy-grid').appendChild(card);
  buggyState.activeWidgets.push({ id, el: card, intervalId });
  buggyState.leakedCount = leakyRegistry.length;

  log(`[BUGGY] Added widget #${id} "${name}" — leakyRegistry size: ${leakyRegistry.length}`, 'leak');
  buggyUpdateStats();
  recordChartPoint();
}

function buggyRemoveById(id) {
  const idx = buggyState.activeWidgets.findIndex(w => w.id === id);
  if (idx === -1) return;

  const { el } = buggyState.activeWidgets[idx];

  // ── We remove it from the DOM — but leakyRegistry still holds the reference ──
  el.remove();
  buggyState.activeWidgets.splice(idx, 1);

  // leakyRegistry is NOT cleaned → object cannot be GC'd
  log(`[BUGGY] Removed widget #${id} from DOM — BUT leakyRegistry still has ${leakyRegistry.length} entries!`, 'warn');
  buggyUpdateStats();
  recordChartPoint();
}

function buggyRemoveLast() {
  if (buggyState.activeWidgets.length === 0) return;
  const last = buggyState.activeWidgets[buggyState.activeWidgets.length - 1];
  buggyRemoveById(last.id);
}

function buggyBulk() {
  for (let i = 0; i < 5; i++) buggyAddWidget();
}

function buggyReset() {
  // Even on "reset" we demonstrate the leak: clear the DOM but keep registry
  buggyState.activeWidgets.forEach(w => w.el.remove());
  buggyState.activeWidgets = [];
  // NOTE: leakyRegistry is intentionally NOT cleared here
  log(`[BUGGY] Reset — DOM cleared but leakyRegistry still holds ${leakyRegistry.length} leaked entries!`, 'warn');
  buggyUpdateStats();
  recordChartPoint();
}

function buggyUpdateStats() {
  document.getElementById('buggy-active').textContent = buggyState.activeWidgets.length;
  document.getElementById('buggy-total').textContent  = buggyState.totalAdded;
  document.getElementById('buggy-leaked').textContent = leakyRegistry.length;
  document.getElementById('buggy-mem').textContent    = (leakyRegistry.length * KB_PER_WIDGET).toLocaleString();
}

/* ═══════════════════════════════════════════════════════════════
   FIXED IMPLEMENTATION
   Every widget is fully cleaned up before removal:
     • clearInterval  → stops the timer
     • removeEventListener → detaches the handler
     • delete registry[id] → drops the last strong reference
   After this, the GC can freely collect the objects.
═══════════════════════════════════════════════════════════════ */

const cleanRegistry = new Map();  // id → entry (properly managed)

const fixedState = {
  activeWidgets : [],
  totalAdded    : 0,
  leakedCount   : 0,   // should stay 0
};

function fixedAddWidget() {
  const id   = ++fixedState.totalAdded;
  const name = WIDGET_NAMES[id % WIDGET_NAMES.length];

  const card = document.createElement('div');
  card.className  = 'widget-card';
  card.dataset.id = id;

  const nameEl = document.createElement('div');
  nameEl.className = 'widget-name';
  nameEl.textContent = name;

  const valEl  = document.createElement('div');
  valEl.className  = 'widget-value';
  valEl.textContent = randomMetric();

  const unitEl = document.createElement('div');
  unitEl.className = 'widget-unit';
  unitEl.textContent = '% utilisation';

  const rmBtn  = document.createElement('button');
  rmBtn.className   = 'widget-remove-btn';
  rmBtn.textContent = '✕';

  card.append(nameEl, valEl, unitEl, rmBtn);

  // ✅ FIX 1: keep a named reference so we can removeEventListener later
  const clickHandler = () => {
    valEl.style.color = '#34d399';
    log(`[FIXED] Widget #${id} clicked`, 'fix');
  };
  card.addEventListener('click', clickHandler);

  // ✅ FIX 2: keep the interval id so we can clearInterval later
  const intervalId = setInterval(() => {
    valEl.textContent = randomMetric();
  }, 800 + Math.random() * 400);

  rmBtn.addEventListener('click', (e) => {
    e.stopPropagation();
    fixedRemoveById(id);
  });

  // ✅ FIX 3: store in a Map we will properly clean up
  cleanRegistry.set(id, {
    id,
    name,
    domNode      : card,
    clickHandler,
    intervalId,
    dataBuffer   : new Array(500).fill(`widget-${id}-data`),
  });

  document.getElementById('fixed-grid').appendChild(card);
  fixedState.activeWidgets.push({ id, el: card });
  fixedState.leakedCount = cleanRegistry.size;

  log(`[FIXED] Added widget #${id} "${name}" — cleanRegistry size: ${cleanRegistry.size}`, 'fix');
  fixedUpdateStats();
  recordChartPoint();
}

function fixedRemoveById(id) {
  const idx = fixedState.activeWidgets.findIndex(w => w.id === id);
  if (idx === -1) return;

  const entry = cleanRegistry.get(id);
  if (entry) {
    // ✅ Stop the interval — no more callbacks keeping the closure alive
    clearInterval(entry.intervalId);

    // ✅ Remove the event listener — handler + closure can now be GC'd
    entry.domNode.removeEventListener('click', entry.clickHandler);

    // ✅ Remove DOM node from the document
    entry.domNode.remove();

    // ✅ Drop the registry entry — last strong reference gone
    cleanRegistry.delete(id);
  }

  fixedState.activeWidgets.splice(idx, 1);
  fixedState.leakedCount = cleanRegistry.size; // should equal activeWidgets.length

  log(`[FIXED] Removed widget #${id} — interval cleared, listener removed, registry entry deleted. cleanRegistry size: ${cleanRegistry.size}`, 'fix');
  fixedUpdateStats();
  recordChartPoint();
}

function fixedRemoveLast() {
  if (fixedState.activeWidgets.length === 0) return;
  const last = fixedState.activeWidgets[fixedState.activeWidgets.length - 1];
  fixedRemoveById(last.id);
}

function fixedBulk() {
  for (let i = 0; i < 5; i++) fixedAddWidget();
}

function fixedReset() {
  // Proper teardown of every active widget
  [...fixedState.activeWidgets].forEach(w => fixedRemoveById(w.id));
  log(`[FIXED] Reset — all widgets fully cleaned up. cleanRegistry size: ${cleanRegistry.size}`, 'fix');
  fixedUpdateStats();
  recordChartPoint();
}

function fixedUpdateStats() {
  document.getElementById('fixed-active').textContent = fixedState.activeWidgets.length;
  document.getElementById('fixed-total').textContent  = fixedState.totalAdded;
  document.getElementById('fixed-leaked').textContent = cleanRegistry.size;
  document.getElementById('fixed-mem').textContent    = (cleanRegistry.size * KB_PER_WIDGET).toLocaleString();
}

