<!-- ── Code diff ── -->
<div class="code-section">
  <h2>🔬 Code Comparison — Spot the Three Leak Patterns</h2>
  <div class="code-tabs">
    <div class="code-tab active-buggy" id="tab-buggy" onclick="showCode('buggy')">🐛 Buggy removeWidget()</div>
    <div class="code-tab"             id="tab-fixed" onclick="showCode('fixed')">✅ Fixed removeWidget()</div>
  </div>

  <div class="code-block visible" id="code-buggy">
    <pre><span class="c-cmt">// ─────────────────────────────────────────────────────────────
// BUGGY VERSION — three leak patterns, all easy to miss
// ─────────────────────────────────────────────────────────────</span>

<span class="c-kw">function</span> <span class="c-fn">addWidget</span>() {
  <span class="c-kw">const</span> id   = ++totalCreated;
  <span class="c-kw">const</span> card = document.<span class="c-fn">createElement</span>(<span class="c-str">'div'</span>);
  card.className = <span class="c-str">'widget-card'</span>;

  <span class="c-cmt">// ❌ LEAK 1 — anonymous handler: can never be removed later</span>
  card.<span class="c-fn">addEventListener</span>(<span class="c-str">'click'</span>, () => {
    <span class="c-fn">console</span>.<span class="c-fn">log</span>(<span class="c-str">`Widget ${id} clicked`</span>);
  });

  <span class="c-cmt">// ❌ LEAK 2 — interval keeps a reference to `card` alive</span>
  <span class="c-kw">const</span> timer = <span class="c-fn">setInterval</span>(() => {
    card.querySelector(<span class="c-str">'.widget-value'</span>).textContent =
      Math.<span class="c-fn">floor</span>(Math.<span class="c-fn">random</span>() * <span class="c-num">1000</span>);
  }, <span class="c-num">1000</span>);

  <span class="c-cmt">// ❌ LEAK 3 — global registry stores the DOM node forever</span>
  widgetRegistry.<span class="c-fn">push</span>({ id, card, timer });

  grid.<span class="c-fn">appendChild</span>(card);
}

<span class="c-kw">function</span> <span class="c-fn">removeWidget</span>(id) {
  <span class="c-kw">const</span> entry = widgetRegistry.<span class="c-fn">find</span>(w => w.id === id);
  <span class="c-kw">if</span> (!entry) <span class="c-kw">return</span>;

<span class="c-del">  // ❌ removeEventListener is NEVER called — listener stays alive</span>
<span class="c-del">  // ❌ clearInterval is NEVER called   — timer keeps card in memory</span>
<span class="c-del">  // ❌ registry entry is NEVER removed  — DOM node ref stays alive</span>

  entry.card.<span class="c-fn">remove</span>();   <span class="c-cmt">// node leaves DOM, but JS still holds it</span>
}</pre>
  </div>

  <div class="code-block" id="code-fixed">
    <pre><span class="c-cmt">// ─────────────────────────────────────────────────────────────
// FIXED VERSION — every reference is explicitly released
// ─────────────────────────────────────────────────────────────</span>

<span class="c-kw">function</span> <span class="c-fn">addWidget</span>() {
  <span class="c-kw">const</span> id   = ++totalCreated;
  <span class="c-kw">const</span> card = document.<span class="c-fn">createElement</span>(<span class="c-str">'div'</span>);
  card.className = <span class="c-str">'widget-card'</span>;

  <span class="c-cmt">// ✅ FIX 1 — named handler so we can pass it to removeEventListener</span>
  <span class="c-kw">function</span> <span class="c-fn">handleClick</span>() {
    <span class="c-fn">console</span>.<span class="c-fn">log</span>(<span class="c-str">`Widget ${id} clicked`</span>);
  }
  card.<span class="c-fn">addEventListener</span>(<span class="c-str">'click'</span>, handleClick);

  <span class="c-cmt">// ✅ FIX 2 — store the timer ID so we can clearInterval later</span>
  <span class="c-kw">const</span> timer = <span class="c-fn">setInterval</span>(() => {
    card.querySelector(<span class="c-str">'.widget-value'</span>).textContent =
      Math.<span class="c-fn">floor</span>(Math.<span class="c-fn">random</span>() * <span class="c-num">1000</span>);
  }, <span class="c-num">1000</span>);

  <span class="c-cmt">// store handler ref alongside timer so removeWidget can reach it</span>
  widgetRegistry.<span class="c-fn">push</span>({ id, card, timer, handleClick });

  grid.<span class="c-fn">appendChild</span>(card);
}

<span class="c-kw">function</span> <span class="c-fn">removeWidget</span>(id) {
  <span class="c-kw">const</span> idx   = widgetRegistry.<span class="c-fn">findIndex</span>(w => w.id === id);
  <span class="c-kw">if</span> (idx === <span class="c-num">-1</span>) <span class="c-kw">return</span>;
  <span class="c-kw">const</span> entry = widgetRegistry[idx];

<span class="c-add">  // ✅ FIX 1 — remove the listener so the card can be collected</span>
<span class="c-add">  entry.card.removeEventListener('click', entry.handleClick);</span>

<span class="c-add">  // ✅ FIX 2 — stop the timer so it no longer references the card</span>
<span class="c-add">  clearInterval(entry.timer);</span>

<span class="c-add">  // ✅ FIX 3 — splice the entry out so the registry releases the node</span>
<span class="c-add">  widgetRegistry.splice(idx, 1);</span>

  entry.card.<span class="c-fn">remove</span>();   <span class="c-cmt">// now truly unreachable → GC can collect it</span>
}</pre>
  </div>
</div>

