<!-- ── Log ── -->
<div class="log-section">
  <h2>📋 Activity Log</h2>
  <div class="log-output" id="log"></div>
</div>

<script>
/* ═══════════════════════════════════════════════════════════════
   Shared helpers
═══════════════════════════════════════════════════════════════ */

let logEl = document.getElementById('log');

function log(msg, type = 'info') {
  const d = document.createElement('div');
  d.className = 'log-entry ' + type;
  const ts = new Date().toLocaleTimeString('en-US', { hour12: false });
  d.textContent = `[${ts}] ${msg}`;
  logEl.appendChild(d);
  logEl.scrollTop = logEl.scrollHeight;
}

function setBar(id, value, max = 50) {
  const pct = Math.min(100, (value / max) * 100);
  const el  = document.getElementById(id);
  if (!el) return;
  el.style.width = pct + '%';
  if (pct > 2) el.textContent = value;
  else          el.textContent = '';
}

function updateViz() {
  const bl = buggy.listenerCount;
  const br = buggy.registry.length;
  const bt = buggy.timerCount;
  const fl = fixed_.listenerCount;
  const fr = fixed_.registry.length;
  const ft = fixed_.timerCount;

  const maxL = Math.max(bl, fl, 1);
  const maxR = Math.max(br, fr, 1);
  const maxT = Math.max(bt, ft, 1);
  const scale = Math.max(maxL, maxR, maxT, 10);

  setBar('viz-buggy-listeners', bl, scale);
  setBar('viz-fixed-listeners', fl, scale);
  setBar('viz-buggy-refs',      br, scale);
  setBar('viz-fixed-refs',      fr, scale);
  setBar('viz-buggy-timers',    bt, scale);
  setBar('viz-fixed-timers',    ft, scale);

  document.getElementById('viz-buggy-listeners-n').textContent = bl;
  document.getElementById('viz-fixed-listeners-n').textContent = fl;
  document.getElementById('viz-buggy-refs-n').textContent      = br;
  document.getElementById('viz-fixed-refs-n').textContent      = fr;
  document.getElementById('viz-buggy-timers-n').textContent    = bt;
  document.getElementById('viz-fixed-timers-n').textContent    = ft;
}

/* ═══════════════════════════════════════════════════════════════
   BUGGY Dashboard
   Leak 1: anonymous addEventListener — can never be removed
   Leak 2: setInterval captures card node — timer never cleared
   Leak 3: global registry never spliced — DOM nodes held forever
═══════════════════════════════════════════════════════════════ */

const buggy = (() => {
  const registry      = [];   // ❌ entries never removed
  let   totalCreated  = 0;
  let   listenerCount = 0;
  let   timerCount    = 0;
  let   widgetIdSeq   = 0;

  const grid = document.getElementById('buggy-grid');

  function updateStats() {
    document.getElementById('buggy-visible').textContent   = grid.querySelectorAll('.widget-card').length;
    document.getElementById('buggy-listeners').textContent = listenerCount;
    document.getElementById('buggy-refs').textContent      = registry.length;
    document.getElementById('buggy-timers').textContent    = timerCount;
    document.getElementById('buggy-total').textContent     = totalCreated;
    updateViz();
  }

  function renderEmpty() {
    if (!grid.querySelector('.widget-card')) {
      grid.innerHTML = '<div class="empty-state">No widgets — click "+ Add Widget"</div>';
    }
  }

  function addWidget() {
    // Remove empty state placeholder
    const empty = grid.querySelector('.empty-state');
    if (empty) empty.remove();

    const id   = ++widgetIdSeq;
    totalCreated++;

    const card = document.createElement('div');
    card.className = 'widget-card';
    card.dataset.id = id;
    card.innerHTML = `
      <div class="widget-title">Widget #${id}</div>
      <div class="widget-value">${Math.floor(Math.random() * 1000)}</div>
      <button class="widget-close" onclick="buggy.removeById(${id})">✕</button>`;

    // ❌ LEAK 1: anonymous function — no way to removeEventListener later
    card.addEventListener('mouseover', () => {
      card.style.borderColor = '#f87171';
    });
    card.addEventListener('mouseout', () => {
      card.style.borderColor = '';
    });
    listenerCount += 2;  // track for demo purposes

    // ❌ LEAK 2: interval captures `card` — never cleared on remove
    const timer = setInterval(() => {
      const v = card.querySelector('.widget-value');
      if (v) v.textContent = Math.floor(Math.random() * 1000);
    }, 800 + Math.random() * 400);
    timerCount++;

    // ❌ LEAK 3: push to registry, never splice on remove
    registry.push({ id, card, timer });

    grid.appendChild(card);
    log(`🐛 [Buggy] Added widget #${id}. Listeners: ${listenerCount}, Refs: ${registry.length}, Timers: ${timerCount}`, 'leak');
    updateStats();
  }

  function removeById(id) {
    const entry = registry.find(w => w.id === id);
    if (!entry) return;

    // ❌ NOT calling removeEventListener
    // ❌ NOT calling clearInterval(entry.timer)
    // ❌ NOT splicing from registry

    entry.card.remove();   // leaves DOM, but registry still holds the node
    log(`🐛 [Buggy] Removed widget #${id} from DOM — but ${registry.length} refs, ${listenerCount} listeners, ${timerCount} timers still alive!`, 'leak');
    renderEmpty();
    updateStats();
  }

  function removeLastWidget() {
    const cards = grid.querySelectorAll('.widget-card');
    if (!cards.length) return;
    const last = cards[cards.length - 1];
    removeById(Number(last.dataset.id));
  }

  function stressTest() {
    for (let i = 0; i < 10; i++) addWidget();
    setTimeout(() => {
      for (let i = 0; i < 10; i++) removeLastWidget();
    }, 300);
  }

  function reset() {
    // Even reset doesn't clean up properly in the buggy version —
    // timers are still running against the old (now-removed) card nodes.
    grid.querySelectorAll('.widget-card').forEach(c => c.remove());
    // ❌ registry NOT cleared, timers NOT cleared, listenerCount NOT reset
    log(`🐛 [Buggy] Reset UI — but ${registry.length} registry entries, ${timerCount} timers still alive in memory!`, 'warn');
    renderEmpty();
    updateStats();
  }

  return {
    addWidget, removeById, removeLastWidget, stressTest, reset,
    get registry()      { return registry; },
    get listenerCount() { return listenerCount; },
    get timerCount()    { return timerCount; },
  };
})();

/* ═══════════════════════════════════════════════════════════════
   FIXED Dashboard
   Fix 1: named handler stored in registry → removeEventListener on teardown
   Fix 2: timer ID stored → clearInterval on teardown
   Fix 3: registry entry spliced on remove
═══════════════════════════════════════════════════════════════ */

const fixed_ = (() => {
  const registry      = [];
  let   totalCreated  = 0;
  let   listenerCount = 0;
  let   timerCount    = 0;
  let   widgetIdSeq   = 0;

  const grid = document.getElementById('fixed-grid');

  function updateStats() {
    document.getElementById('fixed-visible').textContent   = grid.querySelectorAll('.widget-card').length;
    document.getElementById('fixed-listeners').textContent = listenerCount;
    document.getElementById('fixed-refs').textContent      = registry.length;
    document.getElementById('fixed-timers').textContent    = timerCount;
    document.getElementById('fixed-total').textContent     = totalCreated;
    updateViz();
  }

  function renderEmpty() {
    if (!grid.querySelector('.widget-card')) {
      grid.innerHTML = '<div class="empty-state">No widgets — click "+ Add Widget"</div>';
    }
  }

  function addWidget() {
    const empty = grid.querySelector('.empty-state');
    if (empty) empty.remove();

    const id = ++widgetIdSeq;
    totalCreated++;

    const card = document.createElement('div');
    card.className = 'widget-card';
    card.dataset.id = id;
    card.innerHTML = `
      <div class="widget-title">Widget #${id}</div>
      <div class="widget-value">${Math.floor(Math.random() * 1000)}</div>
      <button class="widget-close" onclick="fixed_.removeById(${id})">✕</button>`;

    // ✅ FIX 1: named functions stored so we can removeEventListener later
    function handleOver() { card.style.borderColor = '#4ade80'; }
    function handleOut()  { card.style.borderColor = ''; }
    card.addEventListener('mouseover', handleOver);
    card.addEventListener('mouseout',  handleOut);
    listenerCount += 2;

    // ✅ FIX 2: store timer ID so we can clearInterval on teardown
    const timer = setInterval(() => {
      const v = card.querySelector('.widget-value');
      if (v) v.textContent = Math.floor(Math.random() * 1000);
    }, 800 + Math.random() * 400);
    timerCount++;

    registry.push({ id, card, timer, handleOver, handleOut });

    grid.appendChild(card);
    log(`✅ [Fixed] Added widget #${id}. Listeners: ${listenerCount}, Refs: ${registry.length}, Timers: ${timerCount}`, 'fix');
    updateStats();
  }

  function removeById(id) {
    const idx = registry.findIndex(w => w.id === id);
    if (idx === -1) return;
    const entry = registry[idx];

    // ✅ FIX 1: remove named listeners — card becomes eligible for GC
    entry.card.removeEventListener('mouseover', entry.handleOver);
    entry.card.removeEventListener('mouseout',  entry.handleOut);
    listenerCount -= 2;

    // ✅ FIX 2: stop the timer — no more closure holding the card node
    clearInterval(entry.timer);
    timerCount--;

    // ✅ FIX 3: splice from registry — JS releases the DOM node reference
    registry.splice(idx, 1);

    entry.card.remove();
    log(`✅ [Fixed] Removed widget #${id}. Listeners: ${listenerCount}, Refs: ${registry.length}, Timers: ${timerCount}`, 'fix');
    renderEmpty();
    updateStats();
  }

  function removeLastWidget() {
    const cards = grid.querySelectorAll('.widget-card');
    if (!cards.length) return;
    const last = cards[cards.length - 1];
    removeById(Number(last.dataset.id));
  }

  function stressTest() {
    for (let i = 0; i < 10; i++) addWidget();
    setTimeout(() => {
      for (let i = 0; i < 10; i++) removeLastWidget();
    }, 300);
  }

  function reset() {
    // Properly teardown every widget
    [...registry].forEach(entry => removeById(entry.id));
    log(`✅ [Fixed] Full reset — 0 listeners, 0 refs, 0 timers remain.`, 'fix');
    renderEmpty();
    updateStats();
  }

  return {
    addWidget, removeById, removeLastWidget, stressTest, reset,
    get registry()      { return registry; },
    get listenerCount() { return listenerCount; },
    get timerCount()    { return timerCount; },
  };
})();

