function now() {
  const d = new Date();
  return `${String(d.getHours()).padStart(2,'0')}:` +
         `${String(d.getMinutes()).padStart(2,'0')}:` +
         `${String(d.getSeconds()).padStart(2,'0')}`;
}

function log(logEl, msg, type = 'info') {
  const entry = document.createElement('div');
  entry.className = 'log-entry';
  entry.innerHTML = `<span class="log-time">${now()}</span><span class="log-msg ${type}">${msg}</span>`;
  logEl.prepend(entry);
  // keep log from growing forever in the demo
  while (logEl.children.length > 60) logEl.removeChild(logEl.lastChild);
}

function renderGrid(gridEl, widgets) {
  gridEl.innerHTML = '';
  if (widgets.length === 0) {
    gridEl.innerHTML = '<div class="empty-state">No widgets — click Add Widget</div>';
    return;
  }
  widgets.forEach(w => gridEl.appendChild(w.element));
}

function buildWidgetElement(id, color, onRemove) {
  const el = document.createElement('div');
  el.className = 'widget';
  el.dataset.id = id;
  el.innerHTML = `
    <button class="widget-remove" title="Remove">✕</button>
    <div class="widget-title">Widget #${id}</div>
    <div class="widget-value" id="wv-${id}">0.00</div>
    <div class="widget-bar"><div class="widget-bar-fill" id="wb-${id}" style="width:0%;background:${color}"></div></div>
  `;
  el.querySelector('.widget-remove').addEventListener('click', onRemove);
  return el;
}

function updateWidgetDisplay(widget) {
  const v = document.getElementById(`wv-${widget.id}`);
  const b = document.getElementById(`wb-${widget.id}`);
  if (v) v.textContent = widget.value.toFixed(2);
  if (b) b.style.width = (widget.value * 100).toFixed(1) + '%';
}

// ─────────────────────────────────────────────────────────────────────────────
//  BUGGY version — leaks everything
// ─────────────────────────────────────────────────────────────────────────────
const buggyState = {
  widgets: [],          // active (in DOM)
  leaked:  [],          // removed from DOM but still referenced by closures
  totalCreated: 0,
  leakedListenerCount: 0,
  leakedTimerCount: 0,
};

const buggyLogEl = document.getElementById('buggyLog');

function buggyCreateWidget() {
  const id    = makeWidgetId();
  const color = randomColor();

  const widget = {
    id,
    color,
    value: Math.random(),
    data:  new Array(500).fill(Math.random()), // simulate real data payload
    lastMove: 0,
    width: window.innerWidth,
  };

  // ── BUGGY: we never store these handles ──────────────────────────────────
  // Each closure captures `widget` — keeping it alive forever after removal.

  // 1. Interval — fires every 200 ms, forever
  setInterval(() => {
    widget.value    = Math.random();
    widget.lastTick = Date.now();
    updateWidgetDisplay(widget); // also tries to touch the (possibly removed) DOM
  }, 200);

  // 2. Document mousemove — fires on every mouse movement, forever
  document.addEventListener('mousemove', () => {
    widget.lastMove = Date.now();
  });

  // 3. Window resize — fires on every resize, forever
  window.addEventListener('resize', () => {
    widget.width = window.innerWidth;
  });
  // ── end of leak sources ──────────────────────────────────────────────────

  widget.element = buildWidgetElement(id, color, () => buggyRemoveWidget(widget));

  buggyState.widgets.push(widget);
  buggyState.totalCreated++;
  // Each widget adds 3 listeners + 1 timer
  buggyState.leakedListenerCount += 0; // starts at 0; increments on removal
  buggyState.leakedTimerCount    += 0;

  log(buggyLogEl, `Created widget #${id}`, 'info');
  buggyRefresh();
}

function buggyRemoveWidget(widget) {
  // ── BUGGY removal: only removes the DOM node ─────────────────────────────
  widget.element.remove();
  // The interval, mousemove, and resize listeners are STILL active.
  // They hold a reference to `widget` in their closure.
  // The GC sees: interval → closure → widget  ∴ widget is reachable → NOT collected.

  buggyState.widgets = buggyState.widgets.filter(w => w.id !== widget.id);
  buggyState.leaked.push(widget);           // track for demo purposes
  buggyState.leakedListenerCount += 2;      // mousemove + resize still attached
  buggyState.leakedTimerCount    += 1;      // interval still running

  log(buggyLogEl,
    `⚠ Removed widget #${widget.id} from DOM — but interval & 2 listeners still LIVE`,
    'leak');
  buggyRefresh();
}

function buggyRemoveLast() {
  if (buggyState.widgets.length === 0) return;
  buggyRemoveWidget(buggyState.widgets[buggyState.widgets.length - 1]);
}

function buggyStress() {
  for (let i = 0; i < 10; i++) buggyCreateWidget();
  setTimeout(() => {
    const toRemove = Math.min(10, buggyState.widgets.length);
    for (let i = 0; i < toRemove; i++) buggyRemoveLast();
  }, 300);
}

function buggyReset() {
  // Even reset can't fully clean up — the intervals are still running!
  // We do our best to stop them for the demo's own sanity,
  // but in a real app you'd have no handle to call clearInterval with.
  log(buggyLogEl,
    `↺ Reset attempted — ${buggyState.leakedTimerCount} zombie timers CANNOT be stopped (no handles saved)`,
    'leak');
  buggyState.widgets = [];
  buggyState.leaked  = [];
  buggyState.leakedListenerCount = 0;
  buggyState.leakedTimerCount    = 0;
  buggyState.totalCreated        = 0;
  buggyRefresh();
}

function buggyAdd() { buggyCreateWidget(); }

function buggyRefresh() {
  document.getElementById('buggyActive').textContent    = buggyState.widgets.length;
  document.getElementById('buggyListeners').textContent = buggyState.leakedListenerCount;
  document.getElementById('buggyTimers').textContent    = buggyState.leakedTimerCount;
  document.getElementById('buggyTotal').textContent     = buggyState.totalCreated;
  renderGrid(document.getElementById('buggyGrid'), buggyState.widgets);
  updateMeters();
}

// ─────────────────────────────────────────────────────────────────────────────
//  FIXED version — cleans up properly
// ─────────────────────────────────────────────────────────────────────────────
const fixedState = {
  widgets:      [],
  totalCreated: 0,
};

const fixedLogEl = document.getElementById('fixedLog');

function fixedCreateWidget() {
  const id    = makeWidgetId();
  const color = randomColor();

  const widget = {
    id,
    color,
    value: Math.random(),
    data:  new Array(500).fill(Math.random()),
    lastMove: 0,
    width: window.innerWidth,
  };

  // ── FIXED: store every handle so we can clean up later ───────────────────

  // 1. Store interval ID
  widget.intervalId = setInterval(() => {
    widget.value    = Math.random();
    widget.lastTick = Date.now();
    updateWidgetDisplay(widget);
  }, 200);

  // 2. Store named function reference for mousemove
  widget.onMouseMove = () => {
    widget.lastMove = Date.now();
  };
  document.addEventListener('mousemove', widget.onMouseMove);

  // 3. Store named function reference for resize
  widget.onResize = () => {
    widget.width = window.innerWidth;
  };
  window.addEventListener('resize', widget.onResize);
  // ── end of setup ─────────────────────────────────────────────────────────

  widget.element = buildWidgetElement(id, color, () => fixedRemoveWidget(widget));

  fixedState.widgets.push(widget);
  fixedState.totalCreated++;

  log(fixedLogEl, `Created widget #${id} (handles stored)`, 'info');
  fixedRefresh();
}

function fixedRemoveWidget(widget) {
  // ── FIXED removal: clean up ALL references before touching the DOM ────────

  // 1. Stop the interval — timer handle is gone
  clearInterval(widget.intervalId);

  // 2. Remove the exact same function reference we added
  document.removeEventListener('mousemove', widget.onMouseMove);

  // 3. Remove the resize listener
  window.removeEventListener('resize', widget.onResize);

  // 4. Now remove from DOM — GC can collect the widget object freely
  widget.element.remove();

  fixedState.widgets = fixedState.widgets.filter(w => w.id !== widget.id);

  log(fixedLogEl,
    `✓ Removed widget #${widget.id} — interval cleared, 2 listeners removed, GC-eligible`,
    'clean');
  fixedRefresh();
}

function fixedRemoveLast() {
  if (fixedState.widgets.length === 0) return;
  fixedRemoveWidget(fixedState.widgets[fixedState.widgets.length - 1]);
}

function fixedStress() {
  for (let i = 0; i < 10; i++) fixedCreateWidget();
  setTimeout(() => {
    const toRemove = Math.min(10, fixedState.widgets.length);
    for (let i = 0; i < toRemove; i++) fixedRemoveLast();
  }, 300);
}

function fixedReset() {
  // Clean reset: we CAN properly tear everything down because we saved handles
  [...fixedState.widgets].forEach(w => fixedRemoveWidget(w));
  fixedState.totalCreated = 0;
  log(fixedLogEl, '↺ Full clean reset — all timers stopped, all listeners removed', 'clean');
  fixedRefresh();
}

function fixedAdd() { fixedCreateWidget(); }

function fixedRefresh() {
  document.getElementById('fixedActive').textContent    = fixedState.widgets.length;
  document.getElementById('fixedListeners').textContent = 0;
  document.getElementById('fixedTimers').textContent    = 0;
  document.getElementById('fixedTotal').textContent     = fixedState.totalCreated;
  renderGrid(document.getElementById('fixedGrid'), fixedState.widgets);
  updateMeters();
}

// ─────────────────────────────────────────────────────────────────────────────
//  Memory meter — simulated retained-object count
//  Each leaked widget retains: itself + data array + element ref + 3 closures
//  We model this as 6 "objects" per leak.
// ─────────────────────────────────────────────────────────────────────────────
const OBJECTS_PER_LEAK   = 6;
const OBJECTS_PER_ACTIVE = 3; // active widgets in both panels
const METER_MAX          = 120;

function updateMeters() {
  // Buggy: active widgets + leaked widgets (all still retained)
  const buggyActive  = buggyState.widgets.length;
  const buggyLeaked  = buggyState.leaked.length;
  const buggyObjects = (buggyActive + buggyLeaked) * OBJECTS_PER_LEAK;

  // Fixed: only active widgets; removed ones are GC-eligible
  const fixedObjects = fixedState.widgets.length * OBJECTS_PER_ACTIVE;

  const buggyPct = Math.min(100, (buggyObjects / METER_MAX) * 100);
  const fixedPct = Math.min(100, (fixedObjects / METER_MAX) * 100);

  document.getElementById('buggyMeter').style.width      = buggyPct + '%';
  document.getElementById('fixedMeter').style.width      = fixedPct + '%';
  document.getElementById('buggyMeterCount').textContent = buggyObjects + ' objects';
  document.getElementById('fixedMeterCount').textContent = fixedObjects + ' objects';
}

// ─────────────────────────────────────────────────────────────────────────────
//  Bootstrap — seed both panels with a couple of widgets
// ─────────────────────────────────────────────────────────────────────────────
(function init() {
  for (let i = 0; i < 3; i++) buggyCreateWidget();
  for (let i = 0; i < 3; i++) fixedCreateWidget();
  log(buggyLogEl, '— Demo started — try removing widgets and watch the leak counters —', 'info');
  log(fixedLogEl, '— Demo started — remove widgets freely, counters stay at zero —', 'info');
})();
</script>
</body>
</html>
