<script>
// ─────────────────────────────────────────────
//  Shared helpers
// ─────────────────────────────────────────────
const WIDGET_TYPES = [
  { icon: '🌡️', name: 'Temp',    unit: '°C',  range: [-10, 45]  },
  { icon: '💧', name: 'Humidity', unit: '%',   range: [20, 95]   },
  { icon: '⚡', name: 'Power',   unit: 'W',   range: [0, 500]   },
  { icon: '📡', name: 'Signal',  unit: 'dBm', range: [-90, -30] },
  { icon: '🔋', name: 'Battery', unit: '%',   range: [0, 100]   },
  { icon: '🌬️', name: 'Wind',    unit: 'm/s', range: [0, 30]    },
  { icon: '☀️', name: 'UV Idx',  unit: '',    range: [0, 11]    },
  { icon: '🌊', name: 'Pressure', unit: 'hPa', range: [980,1040] },
];

function randomType() {
  return WIDGET_TYPES[Math.floor(Math.random() * WIDGET_TYPES.length)];
}

function randomVal(range) {
  return (Math.random() * (range[1] - range[0]) + range[0]).toFixed(1);
}

function appendLog(logEl, msg, cls) {
  const d = document.createElement('div');
  d.className = 'log-entry ' + cls;
  d.textContent = msg;
  logEl.appendChild(d);
  logEl.scrollTop = logEl.scrollHeight;
  // Keep log from growing unbounded in the demo
  while (logEl.children.length > 60) logEl.removeChild(logEl.firstChild);
}

// ─────────────────────────────────────────────
//  Graph
// ─────────────────────────────────────────────
const canvas  = document.getElementById('memGraph');
const ctx     = canvas.getContext('2d');
const bugHistory = [];
const fixHistory = [];
const MAX_POINTS = 80;

function resizeCanvas() {
  canvas.width  = canvas.offsetWidth  * window.devicePixelRatio;
  canvas.height = canvas.offsetHeight * window.devicePixelRatio;
}

window.addEventListener('resize', () => { resizeCanvas(); drawGraph(); });
resizeCanvas();

function drawGraph() {
  const W = canvas.width, H = canvas.height;
  ctx.clearRect(0, 0, W, H);

  // Background grid
  ctx.strokeStyle = '#1e2235';
  ctx.lineWidth = 1;
  for (let y = 0; y <= 4; y++) {
    const py = (y / 4) * H;
    ctx.beginPath(); ctx.moveTo(0, py); ctx.lineTo(W, py); ctx.stroke();
  }

  const allVals = [...bugHistory, ...fixHistory, 1];
  const maxVal  = Math.max(...allVals) * 1.15 || 10;

  function drawLine(data, color) {
    if (data.length < 2) return;
    ctx.beginPath();
    ctx.strokeStyle = color;
    ctx.lineWidth   = 2 * window.devicePixelRatio;
    ctx.lineJoin    = 'round';
    data.forEach((v, i) => {
      const x = (i / (MAX_POINTS - 1)) * W;
      const y = H - (v / maxVal) * H * 0.92 - H * 0.04;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.stroke();

    // Fill under line
    ctx.lineTo((data.length - 1) / (MAX_POINTS - 1) * W, H);
    ctx.lineTo(0, H);
    ctx.closePath();
    ctx.fillStyle = color + '22';
    ctx.fill();
  }

  drawLine(bugHistory, '#f87171');
  drawLine(fixHistory, '#34d399');
}

function pushGraphPoint() {
  const bugLeaked = parseInt(document.getElementById('bug-leaked').textContent) || 0;
  const fixLeaked = parseInt(document.getElementById('fix-leaked').textContent) || 0;
  const bugLive   = parseInt(document.getElementById('bug-live').textContent)   || 0;
  const fixLive   = parseInt(document.getElementById('fix-live').textContent)   || 0;

  bugHistory.push(bugLeaked + bugLive);
  fixHistory.push(fixLeaked + fixLive);

  if (bugHistory.length > MAX_POINTS) bugHistory.shift();
  if (fixHistory.length > MAX_POINTS) fixHistory.shift();

  drawGraph();
}

setInterval(pushGraphPoint, 500);

// ─────────────────────────────────────────────
//  BUGGY Dashboard
// ─────────────────────────────────────────────
const buggy = (() => {
  // Simulated global registry — never cleaned up
  const registry = {};
  // Simulated global event listener store — never cleaned up
  const listenerStore = {};

  let totalCreated  = 0;
  let leakedRefs    = 0;
  let activeListeners = 0;

  const grid   = document.getElementById('bug-grid');
  const logEl  = document.getElementById('bug-log');

  function updateStats() {
    const liveCount = Object.keys(registry).filter(k => registry[k] && registry[k]._inDOM).length;
    document.getElementById('bug-live').textContent      = liveCount;
    document.getElementById('bug-listeners').textContent = activeListeners;
    document.getElementById('bug-leaked').textContent    = leakedRefs;
    document.getElementById('bug-total').textContent     = totalCreated;
    renderGrid();
  }

  function renderGrid() {
    grid.innerHTML = '';
    const entries = Object.values(registry).filter(e => e && e._inDOM);
    if (entries.length === 0) {
      grid.innerHTML = '<div class="empty-msg">No widgets — but leaked refs remain!</div>';
      return;
    }
    entries.forEach(entry => {
      const card = document.createElement('div');
      card.className = 'widget-card';
      card.innerHTML = `
        <button class="w-remove" title="Remove">✕</button>
        <div class="w-icon">${entry.type.icon}</div>
        <div class="w-name">${entry.type.name}</div>
        <div class="w-val">${entry.currentVal}${entry.type.unit}</div>`;
      card.querySelector('.w-remove').addEventListener('click', () => removeWidget(entry.id));
      grid.appendChild(card);
    });
  }

  function addWidget() {
    const id   = 'bug_' + (++totalCreated);
    const type = randomType();
    const val  = randomVal(type.range);

    // ── THE BUG: handler closes over the entry object ──
    const tickHandler = () => {
      if (registry[id]) {
        registry[id].currentVal = randomVal(type.range);
        if (registry[id]._inDOM) renderGrid();
      }
    };

    const visHandler = () => {
      // Simulates a document-level listener that captures the node
      if (registry[id]) {
        registry[id].lastVisible = Date.now();
      }
    };

    registry[id] = { id, type, currentVal: val, _inDOM: true, tickHandler, visHandler };

    // ── THE BUG: listeners added to global targets ──
    listenerStore[id] = { tickHandler, visHandler };
    document.addEventListener('visibilitychange', visHandler);
    activeListeners += 2; // tick (simulated) + visibility

    appendLog(logEl, `[ADD]  ${id} (${type.name}) — listeners attached, registry entry created`, 'log-info');
    updateStats();
  }

  function removeWidget(id) {
    if (!registry[id]) return;

    // ── THE BUG: we remove from DOM but NEVER clean up ──
    registry[id]._inDOM = false;
    // registry[id] is NOT deleted  → reference lives on
    // listenerStore[id] is NOT cleared → listener lives on
    // visHandler is NOT removed from document → fires forever
    leakedRefs += 1;

    appendLog(logEl,
      `[REMOVE] ${id} — DOM removed but ` +
      `registry[${id}] still exists! Listener still attached! 🚨`,
      'log-leak'
    );
    updateStats();
  }

  function removeLastWidget() {
    const live = Object.keys(registry).filter(k => registry[k] && registry[k]._inDOM);
    if (live.length) removeWidget(live[live.length - 1]);
  }

  function stress() {
    for (let i = 0; i < 10; i++) addWidget();
    setTimeout(() => {
      const live = Object.keys(registry).filter(k => registry[k] && registry[k]._inDOM);
      live.forEach(k => removeWidget(k));
    }, 300);
  }

  function clearAll() {
    const live = Object.keys(registry).filter(k => registry[k] && registry[k]._inDOM);
    live.forEach(k => removeWidget(k));
    appendLog(logEl, `[CLEAR] Removed ${live.length} widgets — but ${leakedRefs} refs are still leaking!`, 'log-leak');
    updateStats();
  }

  // Simulate tick updates
  setInterval(() => {
    Object.keys(registry).forEach(k => {
      if (registry[k]) registry[k].tickHandler();
    });
  }, 1200);

  return { addWidget, removeLastWidget, stress, clearAll };
})();

// ─────────────────────────────────────────────
//  FIXED Dashboard
// ─────────────────────────────────────────────
const fixed_ = (() => {
  const registry = {};

  let totalCreated    = 0;
  let activeListeners = 0;

  const grid  = document.getElementById('fix-grid');
  const logEl = document.getElementById('fix-log');

  function updateStats() {
    const liveCount = Object.keys(registry).length;
    document.getElementById('fix-live').textContent      = liveCount;
    document.getElementById('fix-listeners').textContent = activeListeners;
    document.getElementById('fix-leaked').textContent    = 0;   // always 0
    document.getElementById('fix-total').textContent     = totalCreated;
    renderGrid();
  }

  function renderGrid() {
    grid.innerHTML = '';
    const entries = Object.values(registry);
    if (entries.length === 0) {
      grid.innerHTML = '<div class="empty-msg">No widgets — and no leaked refs!</div>';
      return;
    }
    entries.forEach(entry => {
      const card = document.createElement('div');
      card.className = 'widget-card';
      card.innerHTML = `
        <button class="w-remove" title="Remove">✕</button>
        <div class="w-icon">${entry.type.icon}</div>
        <div class="w-name">${entry.type.name}</div>
        <div class="w-val">${entry.currentVal}${entry.type.unit}</div>`;
      card.querySelector('.w-remove').addEventListener('click', () => removeWidget(entry.id));
      grid.appendChild(card);
    });
  }

  function addWidget() {
    const id   = 'fix_' + (++totalCreated);
    const type = randomType();
    const val  = randomVal(type.range);

    const tickHandler = () => {
      if (registry[id]) {
        registry[id].currentVal = randomVal(type.range);
        renderGrid();
      }
    };

    const visHandler = () => {
      if (registry[id]) registry[id].lastVisible = Date.now();
    };

    registry[id] = { id, type, currentVal: val, tickHandler, visHandler };
    document.addEventListener('visibilitychange', visHandler);
    activeListeners += 2;

    appendLog(logEl, `[ADD]  ${id} (${type.name}) — listeners attached`, 'log-info');
    updateStats();
  }

  function removeWidget(id) {
    if (!registry[id]) return;
    const entry = registry[id];

    // ── THE FIX: remove listener with exact same reference ──
    document.removeEventListener('visibilitychange', entry.visHandler);
    activeListeners -= 2;

    // ── THE FIX: delete registry entry so GC can collect ──
    delete registry[id];

    appendLog(logEl,
      `[REMOVE] ${id} — listener removed ✓  registry cleared ✓  GC can collect ✓`,
      'log-fix'
    );
    updateStats();
  }

  function removeLastWidget() {
    const keys = Object.keys(registry);
    if (keys.length) removeWidget(keys[keys.length - 1]);
  }

  function stress() {
    for (let i = 0; i < 10; i++) addWidget();
    setTimeout(() => {
      Object.keys(registry).forEach(k => removeWidget(k));
    }, 300);
  }

  function clearAll() {
    const keys = [...Object.keys(registry)];
    keys.forEach(k => removeWidget(k));
    appendLog(logEl, `[CLEAR] All ${keys.length} widgets removed cleanly. Zero leaks.`, 'log-fix');
    updateStats();
  }

  // Simulate tick updates — only for live widgets
  setInterval(() => {
    Object.keys(registry).forEach(k => {
      if (registry[k]) registry[k].tickHandler();
    });
  }, 1200);

  return { addWidget, removeLastWidget, stress, clearAll };
})();
</script>
