  <span class="hl-green">});</span>
}

<span class="hl-purple">function</span> <span class="hl-blue">removeWidget</span>(id) {
  <span class="hl-green">const entry = widgetRegistry.get(id);</span>
  <span class="hl-purple">if</span> (!entry) <span class="hl-purple">return</span>;

