<script>
// ============================================================
// LEAKING DASHBOARD
// Intentionally demonstrates the exact memory leak pattern:
// - DOM references stored in array, never removed on delete
// - Event listeners created with anonymous functions (can't removeEventListener)
// - Intervals created without storing IDs (can't clearInterval)
// ============================================================
const LeakingDashboard = function() {
  // These arrays simulate what happens in real leaky code:
  // module-level or closure-level arrays that accumulate references
  const leakedDOMRefs = [];       // detached DOM nodes pile up here
  const leakedListenerCount = { value: 0 }; // we can't actually track anon listeners
  const leakedIntervals = [];     // interval IDs we "forgot" to store properly

  let widgetIdCounter = 0;
  let createdCount = 0;
  const activeWidgets = []; // just for display tracking

  function log(msg, type = 'info') {
    const logEl = document.getElementById('leak-log');
    const line = document.createElement('div');
    line.className = `log-${type}`;
    const time = new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'});
    line.textContent = `[${time}] ${msg}`;
    logEl.appendChild(line);
    logEl.scrollTop = logEl.scrollHeight;
  }

  function updateStats() {
    document.getElementById('leak-created').textContent = createdCount;
    document.getElementById('leak-listeners').textContent = leakedListenerCount.value;
    document.getElementById('leak-refs').textContent = leakedDOMRefs.length;
    document.getElementById('leak-active').textContent = activeWidgets.length;
    updateGlobalCounter();
  }

  function addWidget() {
    const id = ++widgetIdCounter;
    createdCount++;

    const grid = document.getElementById('leak-grid');
    const empty = grid.querySelector('.empty-state');
    if (empty) empty.remove();

    // Create widget DOM element
    const widget = document.createElement('div');
    widget.className = 'widget';
    widget.id = `leak-widget-${id}`;

    const widgetData = {
      id,
      name: `Widget ${id}`,
      value: Math.floor(Math.random() * 1000),
      history: new Array(50).fill(0).map(() => Math.random()), // simulate data payload
      metadata: { created: Date.now(), tags: [`tag-${id}`, `metric-${id}`] }
    };

    widget.innerHTML = `
      <div class="widget-title">${widgetData.name}</div>
      <div class="widget-value" id="lv-${id}">${widgetData.value}</div>
      <div class="widget-sub">clicks: <span id="lc-${id}">0</span></div>
      <div class="widget-id">id: leak-${id}</div>
    `;

    grid.appendChild(widget);

    // ❌ LEAK #1: Store DOM reference — this ref will NEVER be removed
    // even after the widget is "deleted" from the page
    leakedDOMRefs.push(widget);

    // ❌ LEAK #2: Anonymous event listener — we lose the reference immediately
    // so we can NEVER call removeEventListener with the correct function reference
    // The listener keeps widgetData alive in its closure forever
    let clickCount = 0;
    widget.addEventListener('click', function() {
      // This anonymous closure captures: widget (DOM ref), widgetData (data object),
      // clickCount (local var). All of these stay in memory as long as this
      // listener exists — which is forever since we can't remove it.
      clickCount++;
      const el = document.getElementById(`lc-${id}`);
      if (el) el.textContent = clickCount;
    });
    leakedListenerCount.value++;

    // ❌ LEAK #3: Interval without stored ID
    // We create the interval but don't keep the ID, so clearInterval is impossible.
    // Even after the widget is removed from DOM, this interval keeps firing,
    // holding the closure (and all captured variables) alive.
    setInterval(function() {
      // This closure captures: widget, widgetData, id
      // It fires every second, accessing a detached DOM node after deletion
      widgetData.value = Math.floor(Math.random() * 1000);
      const el = document.getElementById(`lv-${id}`);
      if (el) el.textContent = widgetData.value;
    }, 1000 + Math.random() * 500);
    // ^^^ interval ID not stored — can never be cleared

    activeWidgets.push(id);
    log(`Created widget leak-${id} | DOM refs in memory: ${leakedDOMRefs.length} | Listeners: ${leakedListenerCount.value}`, 'leak');
    updateStats();
  }

  function removeWidget() {
    if (activeWidgets.length === 0) {
      log('No widgets to remove', 'warn');
      return;
    }

    const id = activeWidgets.pop();
    const widget = document.getElementById(`leak-widget-${id}`);

    if (widget) {
      // Remove from DOM — this is the ONLY cleanup done in leaking version
      widget.remove();
    }

    // ❌ leakedDOMRefs[n] still holds reference to the now-detached DOM node
    // ❌ The click event listener is still attached to the detached node
    // ❌ The interval is still running, referencing the detached node
    // ❌ widgetData object is still alive, held by the listener closure and interval closure
    // The GC sees all these references and correctly keeps everything in memory

    const grid = document.getElementById('leak-grid');
    if (activeWidgets.length === 0) {
      grid.innerHTML = '<div class="empty-state">No widgets yet</div>';
    }

    log(`"Deleted" widget leak-${id} | BUT: ${leakedDOMRefs.length} DOM refs still in memory | ${leakedListenerCount.value} listeners still alive`, 'warn');
    log(`  ↳ Detached node leak-${id} is still referenced by leakedDOMRefs[${leakedDOMRefs.length-1}] — GC cannot collect it`, 'leak');
    updateStats();
  }

  return { addWidget, removeWidget, getLeakedRefs: () => leakedDOMRefs.length, getLeakedListeners: () => leakedListenerCount.value };
};

// ============================================================
// FIXED DASHBOARD
// Demonstrates proper cleanup:
// - Named handler references stored for removeEventListener
// - Interval IDs stored for clearInterval
// - DOM references removed from registry on widget deletion
// ============================================================
const FixedDashboard = function() {
  // Clean registry using Map — each entry holds everything needed for cleanup
  const widgetRegistry = new Map();

  let widgetIdCounter = 0;
  let createdCount = 0;
  const activeWidgets = [];

  function log(msg, type = 'info') {
    const logEl = document.getElementById('fixed-log');
    const line = document.createElement('div');
    line.className = `log-${type}`;
    const time = new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'});
    line.textContent = `[${time}] ${msg}`;
    logEl.appendChild(line);
    logEl.scrollTop = logEl.scrollHeight;
  }

  function updateStats() {
    document.getElementById('fixed-created').textContent = createdCount;
    document.getElementById('fixed-listeners').textContent = widgetRegistry.size;
    document.getElementById('fixed-refs').textContent = widgetRegistry.size;
    document.getElementById('fixed-active').textContent = activeWidgets.length;
    updateGlobalCounter();
  }

  function addWidget() {
    const id = ++widgetIdCounter;
    createdCount++;

    const grid = document.getElementById('fixed-grid');
    const empty = grid.querySelector('.empty-state');
    if (empty) empty.remove();

    const widget = document.createElement('div');
    widget.className = 'widget';
    widget.id = `fixed-widget-${id}`;

    const widgetData = {
      id,
      name: `Widget ${id}`,
      value: Math.floor(Math.random() * 1000),
      history: new Array(50).fill(0).map(() => Math.random()),
      metadata: { created: Date.now(), tags: [`tag-${id}`, `metric-${id}`] }
    };

    widget.innerHTML = `
      <div class="widget-title">${widgetData.name}</div>
      <div class="widget-value" id="fv-${id}">${widgetData.value}</div>
      <div class="widget-sub">clicks: <span id="fc-${id}">0</span></div>
      <div class="widget-id">id: fixed-${id}</div>
    `;

    grid.appendChild(widget);

    // ✅ FIX #1: Named handler — reference is preserved so removeEventListener works
    let clickCount = 0;
    const clickHandler = function(e) {
      clickCount++;
      const el = document.getElementById(`fc-${id}`);
      if (el) el.textContent = clickCount;
    };
    widget.addEventListener('click', clickHandler);

    // ✅ FIX #2: Store interval ID so we can clearInterval on cleanup
    const intervalId = setInterval(function() {
      widgetData.value = Math.floor(Math.random() * 1000);
      const el = document.getElementById(`fv-${id}`);
      if (el) el.textContent = widgetData.value;
    }, 1000 + Math.random() * 500);

    // ✅ FIX #3: Registry stores the element reference AND cleanup handles
    // When we delete, we use this registry to clean everything up properly
    widgetRegistry.set(id, {
      element: widget,
      clickHandler,   // named reference for removeEventListener
      intervalId,     // stored ID for clearInterval
      widgetData      // data object (will be GC'd after registry.delete)
    });

    activeWidgets.push(id);
    log(`Created widget fixed-${id} | Registry size: ${widgetRegistry.size} (healthy)`, 'fixed');
    updateStats();
  }

  function removeWidget() {
    if (activeWidgets.length === 0) {
      log('No widgets to remove', 'warn');
      return;
    }

    const id = activeWidgets.pop();
    const entry = widgetRegistry.get(id);

    if (entry) {
      // ✅ CLEANUP STEP 1: Stop the interval — no more closure references from timer
      clearInterval(entry.intervalId);

      // ✅ CLEANUP STEP 2: Remove event listener using the SAME function reference
      // This is only possible because we stored the named handler above
      entry.element.removeEventListener('click', entry.clickHandler);

      // ✅ CLEANUP STEP 3: Remove from DOM
      entry.element.remove();

      // ✅ CLEANUP STEP 4: Delete from registry
      // Now: zero references to entry.element (detached node), zero references to
      // entry.clickHandler, zero references to entry.widgetData
      // The GC will collect all of these on the next cycle — as it should
      widgetRegistry.delete(id);
    }

    const grid = document.getElementById('fixed-grid');
    if (activeWidgets.length === 0) {
      grid.innerHTML = '<div class="empty-state">No widgets yet</div>';
    }

    log(`Deleted widget fixed-${id} | Interval cleared ✓ | Listener removed ✓ | Registry cleaned ✓`, 'fixed');
    log(`  ↳ Registry size: ${widgetRegistry.size} | All references released — GC can now collect widget-${id}`, 'info');
    updateStats();
  }

  return {
    addWidget,
    removeWidget,
    getActiveRefs: () => widgetRegistry.size,
    getActiveListeners: () => widgetRegistry.size
  };
};

