                <button class="btn btn-green" onclick="FixedPanel.addBurst(5)">+ Burst ×5</button>
                <button class="btn btn-green" onclick="FixedPanel.removeAll()">Remove All</button>
            </div>
        </div>
        <div class="panel-body">
