</div>

<!-- ── Log ── -->
<div class="log-section">
    <h3>📋 Memory Event Log
        <button class="btn btn-blue" style="font-size:0.7rem;padding:4px 10px"
                onclick="clearLog()">Clear</button>
    </h3>
    <div class="log-box" id="log-box"></div>
</div>

<!-- ── Code Proof ── -->
<div class="proof">
    <h3>🔬 Exact Code Comparison — The Leak vs The Fix</h3>
    <div class="proof-grid">

        <div class="proof-card">
            <h4 class="bad">❌ Leaking removeWidget()</h4>
            <pre><span class="cmt">// THE BROKEN VERSION</span>
<span class="cmt">// Listener is anonymous — can NEVER</span>
<span class="cmt">// be passed to removeEventListener</span>
<span class="kw">function</span> <span class="fn">addWidget</span>() {
  <span class="kw">const</span> w = { id, element, data };

  <span class="cmt">// ❌ Anonymous fn — no ref kept</span>
  window.<span class="fn">addEventListener</span>(
    <span class="str">'mousemove'</span>,
    (e) => { w.data.x = e.clientX; }
  );

  <span class="cmt">// ❌ Pushed, never spliced out</span>
  leakedWidgetRegistry.<span class="fn">push</span>(w);

  grid.<span class="fn">appendChild</span>(w.element);
}

<span class="kw">function</span> <span class="fn">removeWidget</span>(id) {
  <span class="cmt">// ❌ Removes from DOM only</span>
  <span class="cmt">// Listener: still on window ✗</span>
  <span class="cmt">// Registry: still has ref   ✗</span>
  <span class="cmt">// Object: GC cannot collect ✗</span>
  element.<span class="fn">remove</span>();
}</pre>
        </div>

        <div class="proof-card">
            <h4 class="good">✅ Fixed removeWidget()</h4>
            <pre><span class="cmt">// THE CORRECT VERSION</span>
<span class="cmt">// Named handler stored on object</span>
<span class="kw">function</span> <span class="fn">addWidget</span>() {
  <span class="kw">const</span> w = { id, element, data };

  <span class="cmt">// ✅ Named fn — reference kept</span>
  w.mouseMoveHandler =
    (e) => { w.data.x = e.clientX; };
  window.<span class="fn">addEventListener</span>(
    <span class="str">'mousemove'</span>,
    w.mouseMoveHandler
  );

  fixedWidgetMap.<span class="fn">set</span>(id, w);
  grid.<span class="fn">appendChild</span>(w.element);
}

<span class="kw">function</span> <span class="fn">removeWidget</span>(id) {
  <span class="kw">const</span> w = fixedWidgetMap.<span class="fn">get</span>(id);

  <span class="cmt">// ✅ Remove the exact listener</span>
  window.<span class="fn">removeEventListener</span>(
    <span class="str">'mousemove'</span>,
    w.mouseMoveHandler  <span class="cmt">// same ref</span>
  );

  <span class="cmt">// ✅ Remove from registry</span>
  fixedWidgetMap.<span class="fn">delete</span>(id);

  <span class="cmt">// ✅ Null out DOM ref</span>
  w.element.<span class="fn">remove</span>();
  w.element = <span class="kw">null</span>;
  <span class="cmt">// GC can now collect w ✓</span>
}</pre>
        </div>

    </div>
</div>

<script>
'use strict';

/* ═══════════════════════════════════════════════════════
   SHARED UTILITIES
═══════════════════════════════════════════════════════ */

let totalCreated    = 0;
let totalLeaked     = 0;   // cumulative widgets whose cleanup was skipped
let totalCleaned    = 0;   // cumulative widgets properly cleaned
let orphanListeners = 0;   // running count of un-removed window listeners

const WIDGET_TYPES = [
    { name: 'CPU',      color: '#f97316', unit: '%'  },
    { name: 'RAM',      color: '#ef4444', unit: 'MB' },
    { name: 'Network',  color: '#38bdf8', unit: 'KB' },
    { name: 'Disk I/O', color: '#a78bfa', unit: 'MB' },
    { name: 'Latency',  color: '#f59e0b', unit: 'ms' },
    { name: 'Threads',  color: '#4ade80', unit: ''   },
    { name: 'Errors',   color: '#fb7185', unit: '/s' },
    { name: 'Requests', color: '#34d399', unit: '/s' },
];

function randomType() {
    return WIDGET_TYPES[Math.floor(Math.random() * WIDGET_TYPES.length)];
}

function randomValue(max = 999) {
    return Math.floor(Math.random() * max);
}

function updateStats() {
    document.getElementById('stat-leaked').textContent    = totalLeaked;
    document.getElementById('stat-cleaned').textContent   = totalCleaned;
    document.getElementById('stat-listeners').textContent = orphanListeners;
    document.getElementById('stat-total').textContent     = totalCreated;
    document.getElementById('stat-leak-active').textContent  =
        Object.keys(LeakPanel.widgets).length;
    document.getElementById('stat-fixed-active').textContent =
        FixedPanel.widgets.size;
}

/* ── Log ── */
const logBox = document.getElementById('log-box');

function log(msg, type = 'info') {
    const entry = document.createElement('div');
    entry.className = `log-entry ${type}-entry`;
    const ts = new Date().toLocaleTimeString('en-US', { hour12: false });
    entry.textContent = `[${ts}] ${msg}`;
    logBox.appendChild(entry);
    logBox.scrollTop = logBox.scrollHeight;
    // cap log at 200 entries
    while (logBox.children.length > 200) {
        logBox.removeChild(logBox.firstChild);
    }
}

function clearLog() {
    logBox.innerHTML = '';
    log('Log cleared.', 'info');
}

/* ── Widget value ticker (simulates live data) ── */
function startTicker(widgetObj) {
    widgetObj._ticker = setInterval(() => {
        if (!widgetObj.element) return;
        const valEl = widgetObj.element.querySelector('.widget-value');
        if (valEl) {
            widgetObj.data.value = randomValue();
            valEl.textContent = widgetObj.data.value + widgetObj.data.unit;
        }
    }, 800 + Math.random() * 1200);
}

function stopTicker(widgetObj) {
    if (widgetObj._ticker) {
        clearInterval(widgetObj._ticker);
        widgetObj._ticker = null;
    }
}

/* ═══════════════════════════════════════════════════════
   ❌  LEAKING PANEL
   Three deliberate leaks per widget:
     1. Anonymous mousemove on window — unremovable
     2. Push into leakedWidgetRegistry — never spliced
     3. DOM element removed but JS object keeps .element ref
═══════════════════════════════════════════════════════ */

// This array is the leak registry — it grows forever
const leakedWidgetRegistry = [];

const LeakPanel = (() => {
    const grid    = document.getElementById('leak-grid');
    const widgets = {};   // id → widget object (also kept in leakedWidgetRegistry)

    function createWidget() {
        const id   = ++totalCreated;
        const type = randomType();
        const data = { value: randomValue(), unit: type.unit, x: 0 };

        // Build DOM element
        const el = document.createElement('div');
        el.className   = 'widget';
        el.dataset.wid = id;
        el.innerHTML   = `
            <button class="widget-close" title="Delete widget">✕</button>
            <div class="widget-title">#${id} ${type.name}</div>
            <div class="widget-value" style="color:${type.color}">
                ${data.value}${type.unit}
            </div>
            <div style="font-size:0.62rem;color:#475569;margin-top:4px">
                mouse x: <span class="mx">0</span>
            </div>`;

        const w = { id, element: el, data, type };

        // ─────────────────────────────────────────────────────
        // LEAK #1 — Anonymous arrow function.
        //   • No reference is stored to this handler.
        //   • removeEventListener(type, fn) requires the EXACT
        //     same function reference. Anonymous = impossible.
        //   • window is a GC root → listener list → closure → w
        //   • w can NEVER be collected.
        // ─────────────────────────────────────────────────────
        window.addEventListener('mousemove', (e) => {
            w.data.x = e.clientX;
            const mxEl = w.element && w.element.querySelector('.mx');
            if (mxEl) mxEl.textContent = e.clientX;
        });
        orphanListeners++;

        // ─────────────────────────────────────────────────────
        // LEAK #2 — Global registry never cleaned.
        //   • leakedWidgetRegistry is reachable from global scope.
        //   • GC traces: global → array → w  →  w stays alive.
        // ─────────────────────────────────────────────────────
        leakedWidgetRegistry.push(w);

        // Close button — calls leaking remove
        el.querySelector('.widget-close').addEventListener('click', (e) => {
            e.stopPropagation();
            removeWidget(id);
        });

        startTicker(w);
        widgets[id] = w;
        return w;
    }

    function removeWidget(id) {
        const w = widgets[id];
        if (!w) return;

        // ─────────────────────────────────────────────────────
        // LEAK #3 — DOM removed, but:
        //   • window listener still holds closure → w
        //   • leakedWidgetRegistry[n] still points to w
        //   • w.element still references the detached node
        //   • GC cannot collect w, cannot collect el
        //   • Ticker is also NOT stopped here intentionally
        //     to show the full horror (commented out below)
        // ─────────────────────────────────────────────────────
        // stopTicker(w);   ← deliberately NOT called
        w.element.remove();   // removes from DOM only
        // w.element = null  ← deliberately NOT nulled
        // leakedWidgetRegistry splice ← deliberately NOT done
        // removeEventListener ← impossible (no fn ref) AND not attempted

        delete widgets[id];
        totalLeaked++;

        log(
            `💀 LEAK: Widget #${id} (${w.type.name}) "deleted" from DOM. ` +
            `Listener on window: STILL ACTIVE. Registry entry: STILL EXISTS. ` +
            `Object in memory: CANNOT BE COLLECTED. Orphan listeners: ${orphanListeners}`,
            'leak'
        );

        renderEmpty(grid, widgets);
        updateStats();
    }

    function addWidget() {
        removeEmpty(grid);
        const w = createWidget();
        grid.appendChild(w.element);
        log(
            `💀 LEAK panel: Widget #${w.id} (${w.type.name}) added. ` +
            `Anonymous window listener registered (unremovable). ` +
            `Registry size: ${leakedWidgetRegistry.length}`,
            'warn'
        );
        updateStats();
    }

    function addBurst(n) {
        for (let i = 0; i < n; i++) addWidget();
    }

    function removeAll() {
        const ids = Object.keys(widgets).map(Number);
        ids.forEach(id => removeWidget(id));
        log(
            `💀 LEAK panel: Removed all ${ids.length} widgets from DOM. ` +
            `${orphanListeners} orphaned window listeners remain. ` +
            `leakedWidgetRegistry.length = ${leakedWidgetRegistry.length}`,
            'leak'
        );
        updateStats();
    }

    return { addWidget, addBurst, removeAll, widgets };
})();


/* ═══════════════════════════════════════════════════════
   ✅  FIXED PANEL
   Correct cleanup for each widget:
     1. Named handler stored on object → removeEventListener works
     2. Map entry deleted on removal
     3. DOM ref nulled after removal
     4. Ticker stopped
═══════════════════════════════════════════════════════ */

const FixedPanel = (() => {
    const grid    = document.getElementById('fixed-grid');
    const widgets = new Map();   // id → widget object

    function createWidget() {
        const id   = ++totalCreated;
        const type = randomType();
        const data = { value: randomValue(), unit: type.unit, x: 0 };

        const el = document.createElement('div');
        el.className   = 'widget';
        el.dataset.wid = id;
        el.innerHTML   = `
            <button class="widget-close" title="Delete widget">✕</button>
            <div class="widget-title">#${id} ${type.name}</div>
            <div class="widget-value" style="color:${type.color}">
                ${data.value}${type.unit}
            </div>
            <div style="font-size:0.62rem;color:#475569;margin-top:4px">
                mouse x: <span class="mx">0</span>
            </div>`;

        const w = { id, element: el, data, type };

        // ─────────────────────────────────────────────────────
        // FIX #1 — Named handler stored as property of w.
        //   • We hold the exact reference needed for removal.
        //   • removeEventListener(type, w.mouseMoveHandler) will
        //     find and remove the exact listener.
        // ─────────────────────────────────────────────────────
        w.mouseMoveHandler = (e) => {
            w.data.x = e.clientX;
            const mxEl = w.element && w.element.querySelector('.mx');
            if (mxEl) mxEl.textContent = e.clientX;
        };
        window.addEventListener('mousemove', w.mouseMoveHandler);

        el.querySelector('.widget-close').addEventListener('click', (e) => {
            e.stopPropagation();
            removeWidget(id);
        });

        startTicker(w);

        // ─────────────────────────────────────────────────────
        // FIX #2 — Use a Map (not a leaking array).
        //   • Map.delete(id) fully removes the entry.
        //   • After deletion, no reference from this Map to w.
        // ─────────────────────────────────────────────────────
        widgets.set(id, w);
        return w;
    }

    function removeWidget(id) {
        const w = widgets.get(id);
        if (!w) return;

        // ─────────────────────────────────────────────────────
        // FIX #1 — Remove the exact listener using stored ref.
        //   • window no longer holds any reference to w.
        // ─────────────────────────────────────────────────────
        window.removeEventListener('mousemove', w.mouseMoveHandler);
        w.mouseMoveHandler = null;   // allow closure to be collected

        // ─────────────────────────────────────────────────────
        // FIX #2 — Delete from Map.
        //   • Map no longer holds a reference to w.
        // ─────────────────────────────────────────────────────
        widgets.delete(id);

        // Stop interval so the callback closure is released too
        stopTicker(w);

        // ─────────────────────────────────────────────────────
        // FIX #3 — Remove from DOM and null the reference.
        //   • w.element → null breaks the last strong reference
        //     to the detached DOM node.
        //   • With no more references to w from any live root,
        //     the GC is now FREE to collect both w and el.
        // ─────────────────────────────────────────────────────
        w.element.remove();
        w.element = null;

        totalCleaned++;

        log(
            `✅ FIXED: Widget #${id} (${w.type.name}) fully cleaned. ` +
            `window listener removed. Map entry deleted. DOM ref nulled. ` +
            `Ticker stopped. Object is now GC-eligible.`,
            'fixed'
        );

        renderEmpty(grid, Object.fromEntries(widgets));
        updateStats();
    }

    function addWidget() {
        removeEmpty(grid);
        const w = createWidget();
        grid.appendChild(w.element);
        log(
            `✅ FIXED panel: Widget #${w.id} (${w.type.name}) added. ` +
            `Named handler stored. Map size: ${widgets.size}`,
            'fixed'
        );
        updateStats();
    }

    function addBurst(n) {
        for (let i = 0; i < n; i++) addWidget();
    }

    function removeAll() {
        const ids = [...widgets.keys()];
        ids.forEach(id => removeWidget(id));
        log(
            `✅ FIXED panel: Removed all ${ids.length} widgets. ` +
            `All listeners removed. Map empty. All objects GC-eligible.`,
            'fixed'
        );
        updateStats();
    }

    return { addWidget, addBurst, removeAll, widgets };
})();


/* ── DOM helpers ── */
function renderEmpty(grid, widgetsObj) {
    const count = widgetsObj instanceof Map
        ? widgetsObj.size
        : Object.keys(widgetsObj).length;
    if (count === 0 && !grid.querySelector('.empty-state')) {
        const d = document.createElement('div');
        d.className   = 'empty-state';
        d.textContent = 'All widgets removed. Check the log above.';
        grid.appendChild(d);
    }
}

function removeEmpty(grid) {
    const e = grid.querySelector('.empty-state');
    if (e) e.remove();
}

/* ── Boot ── */
log('Dashboard initialised. Add widgets to either panel to observe memory behaviour.', 'info');
log('TIP: Open DevTools → Memory tab → take heap snapshots to see leaked objects persist.', 'info');
updateStats();
</script>
