   * THE FIX: Use a Map so we can look up and delete entries by id.
   * Store named handler references on each widget entry
   * so we can pass the exact same function to removeEventListener.
   */
  const widgetRegistry = new Map();  // ← cleaned up on delete

  let idCounter      = 0;
  let totalCreated   = 0;
  let activeListeners = 0;

  const gridEl = document.getElementById('fix-grid');
  const logEl  = document.getElementById('fix-log');

  function updateStats() {
    const visible = gridEl.querySelectorAll('.widget').length;

    document.getElementById('fix-created').textContent   = totalCreated;
    document.getElementById('fix-visible').textContent   = visible;
    document.getElementById('fix-leaked').textContent    = 0;   // always 0
    document.getElementById('fix-listeners').textContent = activeListeners;
  }

  function addWidget() {
    const id   = ++idCounter;
    const name = randomName();
    const val  = randomValue();

    const el = document.createElement('div');
    el.className   = 'widget';
    el.dataset.wid = id;

