      <div class="widget-value">${val}%</div>
      <div class="widget-bar">
        <div class="widget-bar-fill" style="width:${val}%"></div>
      </div>`;

    const widgetObj = { id, name, data: { hover: 0, clicks: 0 }, domNode: el };

    /*
     * THE FIX PART 1: Named handler functions.
     * We store them so we can pass the exact same reference
     * to removeEventListener when the widget is deleted.
     * Anonymous functions CANNOT be removed — you need the reference.
     */
    const onMouseMove = () => {
      widgetObj.data.hover++;
    };

