    el.addEventListener('click',     onClick);

    activeListeners += 2;

    /*
     * THE FIX PART 2: Store the handlers WITH the widget entry
     * so deleteWidget can retrieve and remove them.
     */
    widgetObj.handlers = { onMouseMove, onClick };
    widgetRegistry.set(id, widgetObj);   // Map entry, will be deleted

    gridEl.appendChild(el);
    totalCreated++;
    updateStats();

    log(logEl,
      `Widget #${id} created. Registry size: ${widgetRegistry.size}. ` +
      `Active listeners: ${activeListeners}`,
